import React, { useState, useEffect, useRef } from 'react';
import { Book, Copy, Search, Loader2, BookOpen, FilePlus, Volume2, Languages } from 'lucide-react';
import { getQuickDefinition, generateSpeech, translateText } from '../services/gemini';
import { NotebookItem } from '../types';

interface Props {
  onAddToNotebook: (item: Omit<NotebookItem, 'id' | 'timestamp'>) => void;
  activeLanguage: string;
}

interface ContextMenuState {
  visible: boolean;
  x: number;
  y: number;
  text: string;
  source: string; // New field for context source
}

interface DefinitionState {
  visible: boolean;
  loading: boolean;
  text: string | null;
  originalText: string | null;
  translatedText: string | null;
  isTranslated: boolean;
  position: { x: number; y: number };
}

export const GlobalContextLayer: React.FC<Props> = ({ onAddToNotebook, activeLanguage }) => {
  const [menu, setMenu] = useState<ContextMenuState>({ visible: false, x: 0, y: 0, text: '', source: 'Input_Stream' });
  const [definition, setDefinition] = useState<DefinitionState>({ 
      visible: false, 
      loading: false, 
      text: null, 
      originalText: null,
      translatedText: null,
      isTranslated: false,
      position: { x: 0, y: 0 } 
  });
  const [isPlaying, setIsPlaying] = useState(false);
  const [isTranslating, setIsTranslating] = useState(false);

  const menuRef = useRef<HTMLDivElement>(null);
  const defRef = useRef<HTMLDivElement>(null);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 24000 * 2, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  useEffect(() => {
    const handleContextMenu = (e: MouseEvent) => {
      const selection = window.getSelection();
      const text = selection?.toString().trim();

      if (text && text.length > 0) {
        e.preventDefault();
        let x = e.clientX;
        let y = e.clientY;
        if (x + 200 > window.innerWidth) x = window.innerWidth - 210;
        if (y + 150 > window.innerHeight) y = window.innerHeight - 160;

        let source = "Input_Stream";
        let node = selection.anchorNode;
        while(node && node !== document.body) {
            if (node instanceof Element && node.getAttribute('data-source')) {
                source = node.getAttribute('data-source') || "Input_Stream";
                break;
            }
            node = node.parentElement;
        }

        setMenu({ visible: true, x, y, text, source });
        setDefinition(prev => ({ ...prev, visible: false }));
      }
    };

    const handleClick = (e: MouseEvent) => {
      if (menu.visible && menuRef.current && !menuRef.current.contains(e.target as Node)) {
        setMenu(prev => ({ ...prev, visible: false }));
      }
      if (definition.visible && defRef.current && !defRef.current.contains(e.target as Node)) {
          setDefinition(prev => ({ ...prev, visible: false }));
      }
    };

    document.addEventListener('contextmenu', handleContextMenu);
    document.addEventListener('mousedown', handleClick);
    return () => {
      document.removeEventListener('contextmenu', handleContextMenu);
      document.removeEventListener('mousedown', handleClick);
    };
  }, [menu.visible, definition.visible]);

  const handleDefine = async (e: React.MouseEvent) => {
    e.stopPropagation();
    e.nativeEvent.stopImmediatePropagation();

    // Dimensions based on max-h-[400px] + shadow/borders
    const POPUP_WIDTH = 320; 
    const MAX_HEIGHT = 400; 
    const MARGIN = 16;

    let x = menu.x;
    let y = menu.y;

    // Intelligent X positioning
    // 1. Try placing to the right of cursor (default x)
    // 2. If overflow, shift left just enough to fit (slide)
    if (x + POPUP_WIDTH + MARGIN > window.innerWidth) {
        x = window.innerWidth - POPUP_WIDTH - MARGIN;
    }
    // Safety clamp left
    x = Math.max(MARGIN, x);

    // Intelligent Y positioning
    // 1. Try placing below cursor (default y)
    // 2. If overflow, shift up just enough to fit (slide) 
    // This ensures the bottom (Save button) is always visible without jumping too far up
    if (y + MAX_HEIGHT + MARGIN > window.innerHeight) {
        y = window.innerHeight - MAX_HEIGHT - MARGIN;
    }
    // Safety clamp top
    y = Math.max(MARGIN, y);

    setDefinition({ 
        visible: true, 
        loading: true, 
        text: null, 
        originalText: null,
        translatedText: null,
        isTranslated: false,
        position: { x, y } 
    });
    setMenu(prev => ({ ...prev, visible: false }));

    try {
        // Fetch definition in its source language as per requirements
        const def = await getQuickDefinition(menu.text, "the same language as the provided text");
        setDefinition(prev => ({ 
            ...prev, 
            loading: false, 
            text: def,
            originalText: def 
        }));
    } catch (e) {
        setDefinition(prev => ({ ...prev, loading: false, text: "Could not retrieve definition." }));
    }
  };

  const handleTranslateToggle = async () => {
      if (isTranslating || definition.loading || !definition.originalText) return;

      if (definition.isTranslated) {
           setDefinition(prev => ({
              ...prev,
              text: prev.originalText,
              isTranslated: false
          }));
      } else {
          if (definition.translatedText) {
              setDefinition(prev => ({
                  ...prev,
                  text: prev.translatedText,
                  isTranslated: true
              }));
          } else {
              setIsTranslating(true);
              setDefinition(prev => ({ ...prev, loading: true }));
              try {
                  let targetLang = activeLanguage === 'Original' ? 'English' : activeLanguage;

                  // If source is already translated layer, we translate explanation BACK to English/Original
                  if (menu.source === 'Translated_Layer') {
                      targetLang = 'English'; 
                  }

                  const trans = await translateText(definition.originalText, targetLang);
                  setDefinition(prev => ({ 
                      ...prev, 
                      loading: false, 
                      text: trans,
                      translatedText: trans,
                      isTranslated: true
                  }));
              } catch(e) {
                  setDefinition(prev => ({ ...prev, loading: false }));
              } finally {
                  setIsTranslating(false);
              }
          }
      }
  };

  const handlePronounce = async () => {
      if (isPlaying || !menu.text) return;
      setIsPlaying(true);
      let audioUrl: string | null = null;
      try {
          const b64 = await generateSpeech(menu.text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setIsPlaying(false);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setIsPlaying(false);
          }
      } catch (e) {
          console.error(e);
          setIsPlaying(false);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const handleAddToNotebook = () => {
     // Default add: NO definition included
     onAddToNotebook({
         text: menu.text,
         type: menu.text.includes(' ') && menu.text.length > 30 ? 'sentence' : 'word',
         definition: undefined,
         contextSource: menu.source
     });
     setMenu(prev => ({ ...prev, visible: false }));
  };

  const handleSaveWithDefinition = () => {
      // Save WITH definition: captures the currently visible text (original or translated)
      onAddToNotebook({
         text: menu.text,
         type: menu.text.includes(' ') && menu.text.length > 30 ? 'sentence' : 'word',
         definition: definition.text || undefined,
         contextSource: menu.source
      });
      setDefinition(prev => ({ ...prev, visible: false }));
  };

  const formatDefinition = (text: string) => {
      if (!text) return null;
      return text.split('\n\n').map((section, idx) => {
          const parts = section.split(':');
          if (parts.length > 1 && parts[0].length < 25) {
             return (
                 <div key={idx} className="mb-3">
                     <span className="text-[#00f3ff] font-bold uppercase text-[10px] tracking-widest">{parts[0]}:</span>
                     <p className="mt-1 text-zinc-300">{parts.slice(1).join(':').trim()}</p>
                 </div>
             );
          }
          return <p key={idx} className="mb-3 text-zinc-300">{section}</p>;
      });
  };

  return (
    <div className="fixed inset-0 z-[100] pointer-events-none font-sans text-left">
        {menu.visible && (
            <div 
                ref={menuRef}
                className="absolute bg-[#0a0a0c] border border-cyan-900/50 shadow-[0_0_20px_rgba(0,0,0,0.8)] rounded-sm overflow-hidden min-w-[180px] pointer-events-auto animate-fade-in origin-top-left z-[101]"
                style={{ top: menu.y, left: menu.x }}
            >
                <div className="px-3 py-2 bg-zinc-900 border-b border-zinc-800 text-[10px] text-zinc-500 font-mono uppercase truncate max-w-[200px]">
                    {menu.text.length > 20 ? menu.text.substring(0, 20) + '...' : menu.text}
                </div>
                <div className="p-1">
                    <button onClick={handleDefine} className="w-full text-left px-3 py-2 text-zinc-300 hover:bg-[#00f3ff]/10 hover:text-[#00f3ff] text-xs font-mono uppercase flex items-center gap-2 transition-colors rounded-sm"><Search size={14} />Explain / Define</button>
                    <button onClick={handleAddToNotebook} className="w-full text-left px-3 py-2 text-zinc-300 hover:bg-[#00f3ff]/10 hover:text-[#00f3ff] text-xs font-mono uppercase flex items-center gap-2 transition-colors rounded-sm"><FilePlus size={14} />Add to Notebook</button>
                    <button onClick={() => { navigator.clipboard.writeText(menu.text); setMenu(prev => ({ ...prev, visible: false })); }} className="w-full text-left px-3 py-2 text-zinc-500 hover:bg-zinc-800 hover:text-zinc-300 text-xs font-mono uppercase flex items-center gap-2 transition-colors rounded-sm"><Copy size={14} />Copy Text</button>
                </div>
            </div>
        )}

        {definition.visible && (
             <div 
                ref={defRef}
                className="absolute bg-[#050505]/95 backdrop-blur-md border border-[#00f3ff]/30 shadow-[0_0_30px_rgba(0,0,0,0.9)] rounded-lg p-5 w-80 pointer-events-auto animate-fade-in-up origin-top-left z-[102] max-h-[400px] flex flex-col"
                style={{ top: definition.position.y, left: definition.position.x }}
             >
                 <div className="flex items-start justify-between mb-3 shrink-0">
                     <h3 className="text-[#00f3ff] font-bold font-mono text-sm uppercase tracking-wider flex items-center gap-2">
                         <BookOpen size={16} />
                         {definition.isTranslated ? 'Translation' : 'Analysis'}
                     </h3>
                     <div className="flex items-center gap-2">
                         <button
                           onClick={handleTranslateToggle}
                           disabled={isTranslating || definition.loading || !definition.text}
                           className={`transition-colors p-1.5 rounded-sm hover:bg-zinc-900 ${definition.isTranslated || isTranslating ? 'text-[#00f3ff] bg-[#00f3ff]/10' : 'text-zinc-400 hover:text-[#00f3ff]'}`}
                           title={definition.isTranslated ? "Show Source Explanation" : `Translate Explanation to ${activeLanguage}`}
                         >
                            <Languages size={16} />
                         </button>
                         <button
                           onClick={handlePronounce}
                           disabled={isPlaying || definition.loading}
                           className={`text-zinc-400 hover:text-[#00f3ff] transition-colors p-1.5 rounded-sm hover:bg-zinc-900 ${isPlaying ? 'animate-pulse text-[#00f3ff] bg-[#00f3ff]/10' : ''}`}
                           title="Pronounce Selection"
                         >
                            <Volume2 size={16} />
                         </button>
                         <button onClick={() => setDefinition(prev => ({ ...prev, visible: false }))} className="text-zinc-600 hover:text-white transition-colors text-xl p-1">×</button>
                     </div>
                 </div>

                 <div className="mb-4 overflow-y-auto custom-scrollbar flex-1 text-sm">
                     {definition.loading ? (
                         <div className="flex items-center gap-2 text-zinc-500 text-xs font-mono py-2">
                             <Loader2 size={14} className="animate-spin" />
                             Decrypting Neural Data...
                         </div>
                     ) : (
                         <div className="leading-relaxed font-serif border-l-2 border-zinc-800 pl-3 animate-fade-in">
                             {formatDefinition(definition.text || "")}
                         </div>
                     )}
                 </div>

                 <button
                    onClick={handleSaveWithDefinition}
                    className="w-full py-2 bg-zinc-900 hover:bg-[#00f3ff]/20 text-zinc-400 hover:text-[#00f3ff] border border-zinc-800 hover:border-[#00f3ff]/50 rounded-sm text-xs font-mono uppercase transition-all flex items-center justify-center gap-2 shrink-0"
                 >
                     <FilePlus size={14} />
                     Save Analysis to Log
                 </button>
             </div>
        )}
    </div>
  );
};

import { GoogleGenAI, Type, Modality, Chat, Content, Part } from "@google/genai";
import { BookStructure, Chapter, Concept, DictionaryEntry, FileContext } from "../types";

const getAi = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const safeJsonParse = <T>(text: string): T => {
  if (!text) throw new Error("Empty text provided to parser");

  // 1. Remove markdown code blocks
  let clean = text.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();

  // 2. Try direct parse
  try {
    return JSON.parse(clean);
  } catch (e) {
    // 3. Try to extract the first JSON object or array
    const match = clean.match(/(\{[\s\S]*\}|\[[\s\S]*\])/);
    if (match) {
      try {
        return JSON.parse(match[0]);
      } catch (e2) {
        // Fall through to error
      }
    }
    console.error("JSON Parse Failed. Raw text:", text);
    throw new Error("Failed to parse structured data from model response.");
  }
};

export const cleanGenAiText = (text: string): string => {
  if (!text) return "";
  let cleaned = text.replace(/^(Below|Here|Following|This) is the (translation|text).*?:/gi, '');
  cleaned = cleaned.replace(/^(以下是|这是).*(翻译|内容).*?：/gi, '');
  return cleaned
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/`/g, '')
    .replace(/^#+\s/gm, '') 
    .trim();
};

const withRetry = async <T>(fn: () => Promise<T>, retries = 5, delay = 4000): Promise<T> => {
  try {
    return await fn();
  } catch (error: any) {
    const code = error.status || error.response?.status || error.code || 500;
    const message = (error.message || JSON.stringify(error)).toLowerCase();

    console.warn(`Gemini API Request Failed [${code}]. Retries left: ${retries}.`);

    const isRetryable = 
      code === 429 || 
      code === 500 || 
      code === 503 || 
      code === 504 ||
      message.includes('overloaded') ||
      message.includes('quota') || 
      message.includes('internal server error') ||
      message.includes('server error') ||
      message.includes('deadline') ||
      message.includes('timeout') ||
      message.includes('unavailable') ||
      message.includes('fetch failed');

    if (retries > 0 && isRetryable) {
      const nextDelay = delay * 2;
      console.log(`Retrying in ${delay}ms...`);
      await new Promise(resolve => setTimeout(resolve, delay));
      return withRetry(fn, retries - 1, nextDelay);
    }
    throw error;
  }
};

const getFilePart = (file: FileContext): Part => {
  if (file.isText) {
    // Limit to ~1M chars to avoid "Quota exceeded" (429) on large files
    // 1M chars is approx 250k-300k tokens, leaving room in the 1M TPM quota.
    const LIMIT = 1000000;
    const content = file.content.length > LIMIT ? file.content.substring(0, LIMIT) + "\n...[Content Truncated]..." : file.content;
    return { text: content };
  }
  return { inlineData: { mimeType: file.mimeType, data: file.content } };
};

export const analyzeBookStructure = async (file: FileContext): Promise<BookStructure> => {
  return withRetry(async () => {
    const ai = getAi();

    // Switch to gemini-3-flash-preview to avoid rigorous rate limits on Pro
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: {
        parts: [
          getFilePart(file),
          { text: "Analyze the document structure. Return a valid JSON object with 'title', 'author', and 'chapters' (an array of objects with 'id' (number), 'title' (string), and 'description' (string)). Ensure the JSON is clean and strictly follows this schema." }
        ]
      },
      config: {
        systemInstruction: "You are a specialized document parser. Your output must be ONLY a valid JSON object. Do not include markdown code blocks (```json), conversational text, or introductions. If the document is large, identify the main sections as chapters.",
        responseMimeType: "application/json",
        // Flash model efficient thinking budget
        thinkingConfig: { thinkingBudget: 0 },
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            author: { type: Type.STRING },
            chapters: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  id: { type: Type.INTEGER },
                  title: { type: Type.STRING },
                  description: { type: Type.STRING }
                },
                required: ["id", "title"]
              }
            }
          },
          required: ["title", "author", "chapters"]
        }
      }
    });

    if (!response.text) throw new Error("Empty response from model");

    const data = safeJsonParse<any>(response.text);

    // Ensure data integrity
    const chapters = Array.isArray(data.chapters) ? data.chapters.map((c: any, i: number) => ({
        id: c.id || i + 1,
        title: c.title || `Chapter ${i + 1}`,
        description: c.description || ""
    })) : [];

    return { 
        title: data.title || "Untitled Document",
        author: data.author || "Unknown Author",
        chapters: chapters,
        id: crypto.randomUUID(), 
        bookmarks: [] 
    } as BookStructure;
  });
};

export const translateSentences = async (sentences: string[], targetLanguage: string): Promise<string[]> => {
  if (sentences.length === 0) return [];
  const batchSize = 10;
  const results: string[] = [];

  for (let i = 0; i < sentences.length; i += batchSize) {
    const batch = sentences.slice(i, i + batchSize);
    const batchResult = await withRetry(async () => {
      const ai = getAi();
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: {
          parts: [{ text: `Translate the following sentences to ${targetLanguage}. Return a JSON array of strings. Maintain 1:1 mapping.\n\nSentences: ${JSON.stringify(batch)}` }]
        },
        config: {
          responseMimeType: "application/json",
          thinkingConfig: { thinkingBudget: 0 },
          responseSchema: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        }
      });
      return safeJsonParse<string[]>(response.text || "[]");
    });
    results.push(...batchResult);
    if (i + batchSize < sentences.length) {
        await new Promise(r => setTimeout(r, 200));
    }
  }
  return results;
};

export const extractChapterText = async (file: FileContext, chapter: Chapter): Promise<string> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: `Extract the full text for the chapter titled: "${chapter.title}". Use double newlines for paragraph breaks.` }
        ]
      },
      config: {
        thinkingConfig: { thinkingBudget: 0 }
      }
    });
    return response.text || "";
  });
};

export const generatePodcastAudio = async (
  file: FileContext,
  chapter: Chapter,
  tone: string = 'Engaging',
  hosts: { host1: string, voice1: string, host2: string, voice2: string },
  language: string = 'English'
): Promise<{ audio: string; script: string; episodeTitle: string }> => {
  return withRetry(async () => {
    const ai = getAi();
    const scriptResponse = await ai.models.generateContent({
      model: "gemini-3-flash-preview", 
      contents: {
        parts: [
          getFilePart(file),
          { text: `Create a ${tone} podcast dialogue about the chapter "${chapter.title}" in ${language}. Keep the conversation concise (max 600 words). Use hosts ${hosts.host1} and ${hosts.host2}. Output JSON with 'episodeTitle' and 'script'.` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        thinkingConfig: { thinkingBudget: 0 },
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            episodeTitle: { type: Type.STRING },
            script: { type: Type.STRING }
          },
          required: ["episodeTitle", "script"]
        }
      }
    });

    const parsedResponse = safeJsonParse<{ script: string, episodeTitle: string }>(scriptResponse.text || "{}");
    if (!parsedResponse.script) throw new Error("Script generation failed");

    const audioResponse = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: parsedResponse.script }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          multiSpeakerVoiceConfig: {
            speakerVoiceConfigs: [
              { speaker: hosts.host1, voiceConfig: { prebuiltVoiceConfig: { voiceName: hosts.voice1 } } },
              { speaker: hosts.host2, voiceConfig: { prebuiltVoiceConfig: { voiceName: hosts.voice2 } } }
            ]
          }
        }
      }
    });

    const base64Audio = audioResponse.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("Audio generation failed");
    return { audio: base64Audio, script: parsedResponse.script, episodeTitle: parsedResponse.episodeTitle };
  });
};

export const extractConcepts = async (file: FileContext, chapter: Chapter): Promise<Concept[]> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: `Identify 3 key concepts from "${chapter.title}". Return as JSON array of objects with 'term', 'definition', and 'visualPrompt'.` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        thinkingConfig: { thinkingBudget: 0 },
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              term: { type: Type.STRING },
              definition: { type: Type.STRING },
              visualPrompt: { type: Type.STRING }
            },
            required: ["term", "definition", "visualPrompt"]
          }
        }
      }
    });
    return safeJsonParse<Concept[]>(response.text || "[]");
  });
};

export const generateConceptImage = async (visualPrompt: string, style: string = 'Digital Art', aspectRatio: string = '1:1'): Promise<string> => {
  // Mandatory check for API key when using gemini-3-pro-image-preview
  const hasKey = await (window as any).aistudio.hasSelectedApiKey();
  if (!hasKey) {
      await (window as any).aistudio.openSelectKey();
  }

  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts: [{ text: `${style} style: ${visualPrompt}` }] },
      config: { 
          imageConfig: { 
              aspectRatio: aspectRatio as any,
              imageSize: '4K'
          } 
      }
    });
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
    }
    throw new Error("No image generated");
  });
};

export const extractDictionary = async (file: FileContext, chapter: Chapter): Promise<DictionaryEntry[]> => {
  return withRetry(async () => {
    const ai = getAi();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: {
        parts: [
          getFilePart(file),
          { text: `List 5 specialized terms from "${chapter.title}". Return JSON array of objects with 'word', 'context', and 'definition'.` }
        ]
      },
      config: {
        responseMimeType: "application/json",
        thinkingConfig: { thinkingBudget: 0 },
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
