const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.UPLOAD);

  const [library, setLibrary] = useState<LibraryItem[]>([]);
  const [activeBookId, setActiveBookId] = useState<string | null>(null);

  // Notebook State
  const [notebook, setNotebook] = useState<NotebookItem[]>([]);

  const activeBook = library.find(item => item.book.id === activeBookId)?.book || null;
  const activeFileContext = library.find(item => item.book.id === activeBookId)?.fileContext || null;

  const [activeChapterId, setActiveChapterId] = useState<number | null>(null);
  const activeChapter = activeBook?.chapters.find(c => c.id === activeChapterId) || null;

  const [activeTab, setActiveTab] = useState<Tab>(Tab.AUDIOBOOK);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showLibraryList, setShowLibraryList] = useState(false);

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings>({
    targetLanguage: 'Spanish',
    highlightColor: 'indigo',
    textSize: 'base',
    lineHeight: 'normal',
    letterSpacing: 'normal',
    font: 'Inter'
  });

  const handleAddToNotebook = (item: Omit<NotebookItem, 'id' | 'timestamp'>) => {
      // Clean text: remove unnecessary ** markdown
      const cleanedText = item.text.replace(/\*\*/g, '').trim();
      const cleanedDefinition = item.definition ? item.definition.replace(/\*\*/g, '').trim() : undefined;

      // Duplicate Check
      // We check if an item with the same text, book, and chapter already exists
      const isDuplicate = notebook.some(existing => 
          existing.text === cleanedText &&
          existing.bookTitle === (activeBook?.title || item.bookTitle) &&
          existing.sourceChapter === (activeChapter?.title || item.sourceChapter)
      );

      if (isDuplicate) return;

      // Improved classification logic for Words vs Phrases vs Sentences
      let detectedType: 'word' | 'phrase' | 'sentence' = 'word';
      const wordCount = cleanedText.split(/\s+/).length;

      if (wordCount === 1 || cleanedText.length < 15) {
          detectedType = 'word';
      } else if (wordCount <= 6 && cleanedText.length < 50) {
          detectedType = 'phrase';
      } else {
          detectedType = 'sentence';
      }

      const newItem: NotebookItem = {
          ...item,
          text: cleanedText,
          definition: cleanedDefinition,
          id: crypto.randomUUID(),
          timestamp: Date.now(),
          type: detectedType,
          sourceChapter: activeChapter?.title,
          bookTitle: activeBook?.title,
          bookAuthor: activeBook?.author
      };

      setNotebook(prev => [newItem, ...prev]);

      // If no definition is provided (e.g., quick add), fetch one in background
      if (!cleanedDefinition) {
          getQuickDefinition(cleanedText, settings.targetLanguage)
              .then(def => {
                  handleBatchUpdateDefinitions({ [newItem.id]: def });
              })
              .catch(err => {
                  console.error("Auto-definition fetch failed during add:", err);
              });
      }
  };

  const handleDeleteNotebookItem = (id: string) => {
      setNotebook(prev => prev.filter(i => i.id !== id));
  };

  const handleBulkDeleteNotebookItems = (ids: string[]) => {
      setNotebook(prev => prev.filter(i => !ids.includes(i.id)));
  };

  const handleUpdateNotebookComment = (id: string, comment: string) => {
      setNotebook(prev => prev.map(item => item.id === id ? { ...item, comment } : item));
  };

  const handleBatchUpdateDefinitions = (updates: Record<string, string>) => {
      setNotebook(prev => prev.map(item => {
          if (updates[item.id]) {
              return { ...item, definition: updates[item.id] };
          }
          return item;
      }));
  };

  const processEpub = async (file: File): Promise<string> => {
    try {
      const zip = await JSZip.loadAsync(file);

      // Attempt to find the OPF file to determine reading order
      const opfPath = Object.keys(zip.files).find(f => f.toLowerCase().endsWith('.opf'));
      let sortedFiles: string[] = [];
      const parser = new DOMParser();

      if (opfPath) {
          // Robust EPUB Parsing via OPF Spine
          const opfContent = await zip.files[opfPath].async("string");
          const opfDoc = parser.parseFromString(opfContent, "text/xml");

          // 1. Map id -> href (Manifest)
          const manifest: Record<string, string> = {};
          Array.from(opfDoc.getElementsByTagName("item")).forEach(item => {
              const id = item.getAttribute("id");
              const href = item.getAttribute("href");
              if (id && href) manifest[id] = href;
          });

          // 2. Get spine order (idref)
          const spineIds = Array.from(opfDoc.getElementsByTagName("itemref"))
              .map(item => item.getAttribute("idref"))
              .filter(id => id !== null) as string[];

          // 3. Resolve file paths
          const opfDir = opfPath.substring(0, opfPath.lastIndexOf('/') + 1);

          spineIds.forEach(id => {
              if (manifest[id]) {
                  const href = manifest[id];
                  const decodedHref = decodeURIComponent(href);
                  const fullPath = opfDir + decodedHref;

                  if (zip.files[fullPath]) {
                      sortedFiles.push(fullPath);
                  } else {
                      const found = Object.keys(zip.files).find(k => k.endsWith(decodedHref));
                      if (found) sortedFiles.push(found);
                  }
              }
          });
      }

      if (sortedFiles.length === 0) {
          sortedFiles = Object.keys(zip.files).filter(filename => 
            filename.match(/\.(html|xhtml|htm)$/i) && !filename.includes('__MACOSX')
          );
          sortedFiles.sort((a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' }));
      }

      let fullText = "";
      for (const filename of sortedFiles) {
        const content = await zip.files[filename].async("string");
        const processedContent = content
            .replace(/<\/p>/gi, '\n\n')
            .replace(/<\/div>/gi, '\n')
            .replace(/<br\s*\/?>/gi, '\n')
            .replace(/<\/h[1-6]>/gi, '\n\n')
            .replace(/<\/li>/gi, '\n');

        const doc = parser.parseFromString(processedContent, "text/html");
        const text = doc.body.textContent || "";
        fullText += text.trim() + "\n\n";
      }

      if (!fullText) throw new Error("No readable text found in EPUB.");
      if (fullText.length > 5000000) {
          return fullText.substring(0, 5000000) + "\n\n[...Content truncated due to excessive size...]";
      }
      return fullText;

    } catch (e) {
      console.error("EPUB processing error", e);
      throw new Error("Could not parse EPUB file. Structure may be corrupted.");
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const allowedExtensions = ['.pdf', '.txt', '.md', '.html', '.xml', '.epub'];
    const hasAllowedExt = allowedExtensions.some(ext => file.name.toLowerCase().endsWith(ext));

    if (!hasAllowedExt) {
      setError("Supported formats: PDF, EPUB, TXT, MD, HTML.");
      return;
    }

    if (!file.type.startsWith('text/') && !file.name.toLowerCase().endsWith('.epub') && file.size > 50 * 1024 * 1024) {
       setError("PDF too large (>50MB). Please optimize or split the file.");
       return;
    }

    setIsProcessing(true);
    setError(null);

    const reader = new FileReader();
    const isEpub = file.name.toLowerCase().endsWith('.epub');
    const isTextBased = file.type.startsWith('text/') || 
                        ['.txt', '.md', '.html', '.xml'].some(ext => file.name.toLowerCase().endsWith(ext));

    const finalizeUpload = async (context: FileContext) => {
        try {
            const structure = await analyzeBookStructure(context);
            const newItem: LibraryItem = {
                book: structure,
                fileContext: context,
                uploadDate: Date.now()
            };
            setLibrary(prev => [newItem, ...prev]);
            setActiveBookId(structure.id);
            if (structure.chapters.length > 0) setActiveChapterId(structure.chapters[0].id);
            setView(AppView.DASHBOARD);
            setShowLibraryList(false);
        } catch (err: any) {
            console.error("Analysis Error:", err);
            setError("Decoding failed. " + (err.message || "The file might be too complex or the model is busy."));
        } finally {
            setIsProcessing(false);
        }
    };

    if (isEpub) {
       try {
         const textContent = await processEpub(file);
         await finalizeUpload({
            content: textContent,
            mimeType: 'text/plain',
            isText: true
         });
       } catch (err: any) {
         setError(err.message || "Failed to process EPUB.");
         setIsProcessing(false);
       }
       return;
    }

    reader.onload = async (e) => {
      let context: FileContext;
      if (isTextBased) {
          let content = e.target?.result as string;
          if (content.length > 2000000) content = content.substring(0, 2000000) + "... [Truncated]";
          context = { content, mimeType: 'text/plain', isText: true };
      } else {
          const rawBase64 = (e.target?.result as string).split(',')[1];
          // Strip newlines and whitespace which are common in base64 output and break API calls
          const cleanBase64 = rawBase64.replace(/[\r\n\s]+/g, '');
          context = { content: cleanBase64, mimeType: 'application/pdf', isText: false };
      }
      await finalizeUpload(context);
    };

    if (isTextBased) reader.readAsText(file);
    else reader.readAsDataURL(file);
  };

  const toggleBookmark = (chapterId: number) => {
    if (!activeBookId) return;
    setLibrary(prev => prev.map(item => {
        if (item.book.id === activeBookId) {
            const bookmarks = item.book.bookmarks || [];
            const isBookmarked = bookmarks.includes(chapterId);
            const newBookmarks = isBookmarked 
                ? bookmarks.filter(id => id !== chapterId)
                : [...bookmarks, chapterId];
            return { ...item, book: { ...item.book, bookmarks: newBookmarks } };
        }
        return item;
    }));
  };

  const renderContent = () => {
    if (activeTab === Tab.NOTEBOOK) {
        return (
            <Notebook 
                items={notebook} 
                onDelete={handleDeleteNotebookItem} 
                onBulkDelete={handleBulkDeleteNotebookItems} 
                onUpdateComment={handleUpdateNotebookComment} 
                onBatchUpdateDefinitions={handleBatchUpdateDefinitions}
                settings={settings} 
            />
        );
    }

    if (!activeChapter || !activeFileContext) return null;

    let content;
    switch (activeTab) {
      case Tab.AUDIOBOOK:
        content = <AudioBook chapter={activeChapter} fileContext={activeFileContext} settings={settings} onSettingsUpdate={setSettings} />;
        break;
      case Tab.PODCAST:
        content = <PodcastPlayer chapter={activeChapter} fileContext={activeFileContext} settings={settings} />;
        break;
      case Tab.CONCEPTS:
        content = <Visualizer chapter={activeChapter} fileContext={activeFileContext} />;
        break;
      case Tab.ANIMATION:
        content = <VideoSummary chapter={activeChapter} fileContext={activeFileContext} />;
        break;
      default:
        content = null;
    }

    return (
      <div key={`${activeBookId}-${activeChapter.id}-${activeTab}`} className="h-full animate-fade-in">
        {content}
      </div>
    );
  };

  if (view === AppView.UPLOAD) {
    return (
      <div className="min-h-screen bg-[#020202] bg-grid flex flex-col items-center justify-center p-6 relative overflow-hidden font-tech text-left">
        <div className="absolute top-8 left-8 w-24 h-24 border-l border-t border-zinc-800 rounded-tl-lg pointer-events-none"></div>
        <div className="absolute bottom-8 right-8 w-24 h-24 border-r border-b border-zinc-800 rounded-br-lg pointer-events-none"></div>

        <div className="z-10 max-w-lg w-full text-center space-y-12">
          <div className="space-y-2 animate-fade-in-up text-center">
             <div className="flex items-center justify-center gap-2 mb-4">
                <Terminal size={32} className="text-[#00f3ff]" />
             </div>
            <h1 className="text-7xl font-bold tracking-tighter text-white drop-shadow-[0_0_25px_rgba(0,243,255,0.3)]">
              Decod<span className="text-[#00f3ff]">Ebook</span>
            </h1>
            <p className="text-zinc-500 tracking-[0.2em] text-xs uppercase">
              V.4.2 // Neural Text Decoding Interface
            </p>
          </div>

          <div className="relative group animate-fade-in-up hud-border bg-[#050505] p-10 transition-all duration-500 hover:shadow-[0_0_30px_rgba(0,243,255,0.1)]" style={{ animationDelay: '0.1s' }}>
              {isProcessing ? (
                <Loader text="DECODING_SOURCE..." />
              ) : (
                <div className="relative flex flex-col items-center justify-center space-y-8">
                  <div className="relative">
                    <div className="w-32 h-32 bg-[#0a0a0c] border border-zinc-800 rounded-full flex items-center justify-center group-hover:border-[#00f3ff] transition-all duration-500">
                        <Upload className="w-12 h-12 text-zinc-600 group-hover:text-[#00f3ff] transition-colors" />
                    </div>
                    <div className="absolute -inset-2 border border-dashed border-zinc-800 rounded-full animate-spin-slow pointer-events-none group-hover:border-[#00f3ff]/30"></div>
                  </div>
                  <div className="space-y-2 text-center">
                    <p className="text-[#00f3ff] font-bold uppercase tracking-widest text-sm animate-pulse">Initialize Upload</p>
                    <p className="text-[10px] text-zinc-600 font-mono">SUPPORTED PROTOCOLS: PDF / EPUB / TXT / MD</p>
                  </div>
                  <input 
                    type="file" 
                    accept=".pdf,.txt,.md,.html,.xml,.epub"
                    onChange={handleFileUpload}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  />
                </div>
              )}
          </div>

          {library.length > 0 && (
             <button 
                onClick={() => setView(AppView.DASHBOARD)}
                className="text-zinc-500 hover:text-[#00f3ff] text-xs font-mono uppercase tracking-widest transition-colors flex items-center gap-2 mx-auto border border-transparent hover:border-[#00f3ff]/30 px-4 py-2 rounded-sm"
             >
                <LibraryIcon size={14} />
                Access_Data_Bank [{library.length}]
             </button>
          )}
          {error && <p className="text-[#ff003c] text-xs font-mono border border-[#ff003c]/30 p-2 bg-[#ff003c]/5">{error}</p>}
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-[#020202] bg-grid text-zinc-300 overflow-hidden font-sans relative text-left">
      <GlobalContextLayer onAddToNotebook={handleAddToNotebook} activeLanguage={settings.targetLanguage} />
      <AIAssistant 
        fileContext={activeFileContext} 
        bookTitle={activeBook?.title} 
        bookId={activeBook?.id} 
      />
      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)}
        settings={settings}
        onUpdate={setSettings}
      />

      <aside 
        className={`${isSidebarOpen ? 'w-80' : 'w-0'} bg-[#050505] flex flex-col overflow-hidden relative z-20 transition-all duration-300 border-r border-zinc-900`}
      >
        <div className="p-4 border-b border-zinc-900 shrink-0 bg-black/80 backdrop-blur-sm relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-[1px] bg-[#00f3ff] opacity-20"></div>
            <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-2">
                    <Cpu size={16} className="text-[#00f3ff]" />
                    <span className="text-xs font-tech font-bold text-white tracking-[0.2em]">DECOD.EBOOK</span>
                </div>
                <button 
                    onClick={() => setView(AppView.UPLOAD)} 
                    className="p-1.5 rounded-sm hover:bg-zinc-900 text-zinc-600 hover:text-[#00f3ff] transition-colors"
                    title="Upload New"
                >
                    <Upload size={14} />
                </button>
            </div>
            {!showLibraryList && activeBook && (
                <div className="mt-4 p-3 border border-zinc-800 bg-zinc-900/20 rounded-sm relative group cursor-default">
                    <div className="absolute top-0 right-0 w-2 h-2 border-t border-r border-[#00f3ff]"></div>
                    <div className="absolute bottom-0 left-0 w-2 h-2 border-b border-l border-[#00f3ff]"></div>
                    <h1 className="font-bold text-xs text-white truncate leading-tight mb-1 font-tech uppercase tracking-wide">{activeBook.title}</h1>
                    <p className="text-[9px] text-zinc-500 truncate font-mono uppercase">{activeBook.author}</p>
                    <div className="mt-2 text-[9px] text-[#00f3ff] font-mono flex items-center gap-1">
                        <Activity size={10} /> SYS.ACTIVE
                    </div>
                </div>
            )}
        </div>
        <div className="flex-1 overflow-y-auto p-0 custom-scrollbar">
          {showLibraryList ? (
             <div className="flex flex-col animate-fade-in">
                {library.map(item => (
                    <button
                        key={item.book.id}
                        onClick={() => {
                            setActiveBookId(item.book.id);
                            if(item.book.chapters.length > 0) setActiveChapterId(item.book.chapters[0].id);
                            setShowLibraryList(false);
                        }}
                        className={`w-full flex items-center gap-3 p-4 border-b border-zinc-900 transition-all group ${
                            activeBookId === item.book.id 
                            ? 'bg-[#00f3ff]/5' 
                            : 'hover:bg-zinc-900'
                        }`}
                    >
                        <div className={`w-1 h-8 ${activeBookId === item.book.id ? 'bg-[#00f3ff]' : 'bg-zinc-800'}`}></div>
                        <div className="text-left min-w-0">
                            <h4 className={`text-[10px] font-bold truncate font-tech uppercase tracking-wide ${activeBookId === item.book.id ? 'text-[#00f3ff]' : 'text-zinc-400'}`}>
                                {item.book.title}
                            </h4>
                            <p className="text-[9px] text-zinc-600 truncate font-mono">{item.book.chapters.length} DATA_BLOCKS</p>
                        </div>
                    </button>
                ))}
             </div>
          ) : (
             <div className="py-2 animate-fade-in">
                {activeBook?.chapters.map((chapter, idx) => {
                    const isBookmarked = activeBook.bookmarks?.includes(chapter.id);
                    return (
                        <div key={chapter.id} className="relative group flex items-center justify-between px-4 py-2 hover:bg-zinc-900/50">
                            <button
                                onClick={() => setActiveChapterId(chapter.id)}
                                className={`flex-1 text-left flex items-center gap-3 border-l-2 py-1 transition-all min-w-0 pr-2 ${
                                    activeChapterId === chapter.id 
                                    ? 'border-[#00f3ff]' 
                                    : 'border-transparent'
                                }`}
                            >
                                <span className={`text-[9px] font-mono w-6 text-right shrink-0 ${activeChapterId === chapter.id ? 'text-[#00f3ff]' : 'text-zinc-700'}`}>
                                    {String(idx + 1).padStart(2, '0')}
                                </span>
                                <div className="min-w-0 flex-1 text-left">
                                    <p className={`font-medium truncate font-tech uppercase tracking-tight text-xs ${activeChapterId === chapter.id ? 'text-white' : 'text-zinc-500'}`}>
                                        {chapter.title}
                                    </p>
                                </div>
                            </button>
                            <button 
                                onClick={(e) => { e.stopPropagation(); toggleBookmark(chapter.id); }}
                                className={`p-1.5 transition-colors shrink-0 ${isBookmarked ? 'text-amber-400' : 'text-zinc-800 hover:text-zinc-500'}`}
                                title={isBookmarked ? "Remove Bookmark" : "Add Bookmark"}
                            >
                                <Tag size={12} fill={isBookmarked ? "currentColor" : "none"} />
                            </button>
                        </div>
                    );
                })}
             </div>
          )}
        </div>
        <div className="p-0 border-t border-zinc-900 bg-black flex flex-col shrink-0">
          <button 
            onClick={() => setShowLibraryList(!showLibraryList)}
            className={`w-full flex items-center justify-between p-4 transition-all text-[10px] font-bold font-tech uppercase tracking-widest border-b border-zinc-900/30 ${
                showLibraryList ? 'text-[#00f3ff] bg-[#00f3ff]/5' : 'text-zinc-500 hover:bg-zinc-900 hover:text-[#00f3ff]'
            }`}
          >
             <div className="flex items-center gap-3">
                <Database size={14} />
                <span>{showLibraryList ? "SESSION_DATA" : "DATA_BANKS"}</span>
             </div>
             <span className={`text-[8px] animate-pulse ${showLibraryList ? 'text-[#00f3ff]' : 'text-zinc-700'}`}>●</span>
          </button>
          <button 
            onClick={() => setIsSettingsOpen(true)}
            className="w-full flex items-center gap-3 p-4 hover:bg-zinc-900 text-zinc-500 hover:text-[#00f3ff] transition-colors text-[10px] font-bold font-tech uppercase tracking-widest"
          >
            <SettingsIcon size={14} />
            <span>SYS_CONFIG</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 relative bg-transparent z-10 text-left">
        <header className="h-14 border-b border-zinc-900 flex items-center justify-between px-4 bg-black/90 backdrop-blur-md sticky top-0 z-30 shrink-0">
          <div className="flex items-center gap-4">
            <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="text-zinc-500 hover:text-[#00f3ff] transition-colors">
              {isSidebarOpen ? <X size={18} /> : <Menu size={18} />}
            </button>
            <div className="h-4 w-[1px] bg-zinc-800 mx-1"></div>
            {activeChapterId ? (
                <div className="flex items-center gap-2">
                    <span className="text-[9px] font-mono text-zinc-600 bg-zinc-900 border border-zinc-800 px-1.5 py-0.5">
                        SEC.{String(activeChapterId || 0).padStart(2, '0')}
                    </span>
                    <ChevronRight size={12} className="text-zinc-700" />
                    <span className="text-xs font-bold text-[#00f3ff] font-tech tracking-wide truncate max-w-[200px]">
                        {activeChapter?.title.toUpperCase()}
                    </span>
                </div>
            ) : (
                <span className="text-xs font-tech text-zinc-500 tracking-widest">AWAITING_INPUT</span>
            )}
          </div>

          <div className="flex items-center bg-zinc-950 border border-zinc-900 p-0.5 rounded-sm">
            {[
              { id: Tab.AUDIOBOOK, icon: Headphones, label: "VOICE_SYNTH" },
              { id: Tab.PODCAST, icon: Mic2, label: "NET_CAST" },
              { id: Tab.CONCEPTS, icon: ImageIcon, label: "VISUAL_CORE" },
              { id: Tab.ANIMATION, icon: Film, label: "CINE_RENDER" },
              { id: Tab.NOTEBOOK, icon: NotebookIcon, label: "MEM_LOG" },
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as Tab)}
                className={`flex items-center justify-center gap-2 w-[120px] py-1.5 transition-all text-[9px] font-bold uppercase tracking-wider font-tech ${
                  activeTab === tab.id 
                    ? 'bg-[#00f3ff]/10 text-[#00f3ff] shadow-[0_0_10px_rgba(0,243,255,0.1)]'
                    : 'text-zinc-600 hover:text-zinc-300 hover:bg-zinc-900'
                }`}
              >
                <tab.icon size={12} className={activeTab === tab.id ? 'text-[#00f3ff]' : ''} />
                <span className="hidden xl:inline">{tab.label}</span>
              </button>
            ))}
          </div>
        </header>

        <div className="flex-1 p-0 overflow-hidden relative">
          <div className="h-full w-full p-2 overflow-y-auto custom-scrollbar">
             {renderContent()}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Upload, BookOpen, Headphones, Image as ImageIcon, BookA, Film, Menu, X, ChevronRight, FileText, Mic2, Settings as SettingsIcon, Library as LibraryIcon, Tag, Bookmark, Cpu, Notebook as NotebookIcon, Terminal, Activity, Database, Shield } from 'lucide-react';
import JSZip from 'jszip';
import { BookStructure, Chapter, AppView, Tab, FileContext, AppSettings, LibraryItem, NotebookItem } from '../types';
import { analyzeBookStructure, getQuickDefinition } from '../services/gemini';
import { PodcastPlayer } from './PodcastPlayer';
import { Visualizer } from './Visualizer';
import { VideoSummary } from './VideoSummary';
import { AudioBook } from './AudioBook';
import { Notebook } from './Notebook';
import { SettingsModal } from './SettingsModal';
import { GlobalContextLayer } from './GlobalContextLayer';
import { Loader } from './ui/Loader';
import { AIAssistant } from './AIAssistant';

const App: React.FC = () => {
  const [view, setView] = useState<AppView>(AppView.UPLOAD);

  const [library, setLibrary] = useState<LibraryItem[]>([]);
  const [activeBookId, setActiveBookId] = useState<string | null>(null);

  // Notebook State
  const [notebook, setNotebook] = useState<NotebookItem[]>([]);

  const activeBook = library.find(item => item.book.id === activeBookId)?.book || null;
  const activeFileContext = library.find(item => item.book.id === activeBookId)?.fileContext || null;

  const [activeChapterId, setActiveChapterId] = useState<number | null>(null);
  const activeChapter = activeBook?.chapters.find(c => c.id === activeChapterId) || null;

  const [activeTab, setActiveTab] = useState<Tab>(Tab.AUDIOBOOK);
  const [isSidebarOpen, setSidebarOpen] = useState(true);
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showLibraryList, setShowLibraryList] = useState(false);

  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [settings, setSettings] = useState<AppSettings>({
    targetLanguage: 'Spanish',
    highlightColor: 'indigo',
    textSize: 'base',
    lineHeight: 'normal',
    letterSpacing: 'normal',
    font: 'Inter'
  });

  const handleAddToNotebook = (item: Omit<NotebookItem, 'id' | 'timestamp'>) => {
      // 1. Clean unnecessary markdown asterisks
      const cleanedText = item.text.replace(/\*\*/g, '').trim();
      const cleanedDefinition = item.definition ? item.definition.replace(/\*\*/g, '').trim() : undefined;
      const cleanedComment = item.comment ? item.comment.replace(/\*\*/g, '').trim() : undefined;

      // 2. Check for duplicates
      // Determine what constitutes a "duplicate": same text, same book, same chapter.
      const isDuplicate = notebook.some(existing => 
          existing.text === cleanedText &&
          existing.bookTitle === (activeBook?.title || item.bookTitle) &&
          existing.sourceChapter === (activeChapter?.title || item.sourceChapter)
      );

      if (isDuplicate) return;

      // Improved classification logic for Words vs Phrases vs Sentences based on cleaned text
      let detectedType: 'word' | 'phrase' | 'sentence' = 'word';
      const wordCount = cleanedText.split(/\s+/).length;

      if (wordCount === 1 || cleanedText.length < 15) {
          detectedType = 'word';
      } else if (wordCount <= 6 && cleanedText.length < 50) {
          detectedType = 'phrase';
      } else {
          detectedType = 'sentence';
      }

      const newItem: NotebookItem = {
          ...item,
          text: cleanedText,
          definition: cleanedDefinition,
          comment: cleanedComment,
          id: crypto.randomUUID(),
          timestamp: Date.now(),
          type: detectedType,
          sourceChapter: activeChapter?.title,
          bookTitle: activeBook?.title,
          bookAuthor: activeBook?.author
      };

      setNotebook(prev => [newItem, ...prev]);

      // If no definition is provided (e.g., quick add), fetch one in background
      if (!cleanedDefinition) {
          getQuickDefinition(cleanedText, settings.targetLanguage)
              .then(def => {
                  handleBatchUpdateDefinitions({ [newItem.id]: def });
              })
              .catch(err => {
                  console.error("Auto-definition fetch failed during add:", err);
              });
      }
  };

  const handleDeleteNotebookItem = (id: string) => {
      setNotebook(prev => prev.filter(i => i.id !== id));
  };

  const handleBulkDeleteNotebookItems = (ids: string[]) => {
      setNotebook(prev => prev.filter(i => !ids.includes(i.id)));
  };

  const handleUpdateNotebookComment = (id: string, comment: string) => {
      setNotebook(prev => prev.map(item => item.id === id ? { ...item, comment } : item));
  };

  const handleBatchUpdateDefinitions = (updates: Record<string, string>) => {
      setNotebook(prev => prev.map(item => {
          if (updates[item.id]) {
              return { ...item, definition: updates[item.id] };
          }
          return item;
      }));
  };

  const processEpub = async (file: File): Promise<string> => {
    try {
      const zip = await JSZip.loadAsync(file);

      // Attempt to find the OPF file to determine reading order
      const opfPath = Object.keys(zip.files).find(f => f.toLowerCase().endsWith('.opf'));
      let sortedFiles: string[] = [];
      const parser = new DOMParser();

      if (opfPath) {
          // Robust EPUB Parsing via OPF Spine
          const opfContent = await zip.files[opfPath].async("string");
          const opfDoc = parser.parseFromString(opfContent, "text/xml");

          // 1. Map id -> href (Manifest)
          const manifest: Record<string, string> = {};
          Array.from(opfDoc.getElementsByTagName("item")).forEach(item => {
              const id = item.getAttribute("id");
              const href = item.getAttribute("href");
              if (id && href) manifest[id] = href;
          });

          // 2. Get spine order (idref)
          const spineIds = Array.from(opfDoc.getElementsByTagName("itemref"))
              .map(item => item.getAttribute("idref"))
              .filter(id => id !== null) as string[];

          // 3. Resolve file paths
          const opfDir = opfPath.substring(0, opfPath.lastIndexOf('/') + 1);

          spineIds.forEach(id => {
              if (manifest[id]) {
                  const href = manifest[id];
                  const decodedHref = decodeURIComponent(href);
                  const fullPath = opfDir + decodedHref;

                  if (zip.files[fullPath]) {
                      sortedFiles.push(fullPath);
                  } else {
                      const found = Object.keys(zip.files).find(k => k.endsWith(decodedHref));
                      if (found) sortedFiles.push(found);
                  }
              }
          });
      }

      if (sortedFiles.length === 0) {
          sortedFiles = Object.keys(zip.files).filter(filename => 
            filename.match(/\.(html|xhtml|htm)$/i) && !filename.includes('__MACOSX')
          );
          sortedFiles.sort((a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' }));
      }

      let fullText = "";
      for (const filename of sortedFiles) {
        const content = await zip.files[filename].async("string");
        const processedContent = content
            .replace(/<\/p>/gi, '\n\n')
            .replace(/<\/div>/gi, '\n')
            .replace(/<br\s*\/?>/gi, '\n')
            .replace(/<\/h[1-6]>/gi, '\n\n')
            .replace(/<\/li>/gi, '\n');

        const doc = parser.parseFromString(processedContent, "text/html");
        const text = doc.body.textContent || "";
        fullText += text.trim() + "\n\n";
      }

      if (!fullText) throw new Error("No readable text found in EPUB.");
      if (fullText.length > 5000000) {
          return fullText.substring(0, 5000000) + "\n\n[...Content truncated due to excessive size...]";
      }
      return fullText;

    } catch (e) {
      console.error("EPUB processing error", e);
      throw new Error("Could not parse EPUB file. Structure may be corrupted.");
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const allowedExtensions = ['.pdf', '.txt', '.md', '.html', '.xml', '.epub'];
    const hasAllowedExt = allowedExtensions.some(ext => file.name.toLowerCase().endsWith(ext));

    if (!hasAllowedExt) {
      setError("Supported formats: PDF, EPUB, TXT, MD, HTML.");
      return;
    }

    if (!file.type.startsWith('text/') && !file.name.toLowerCase().endsWith('.epub') && file.size > 50 * 1024 * 1024) {
       setError("PDF too large (>50MB). Please optimize or split the file.");
       return;
    }

    setIsProcessing(true);
    setError(null);

    const reader = new FileReader();
    const isEpub = file.name.toLowerCase().endsWith('.epub');
    const isTextBased = file.type.startsWith('text/') || 
                        ['.txt', '.md', '.html', '.xml'].some(ext => file.name.toLowerCase().endsWith(ext));

    const finalizeUpload = async (context: FileContext) => {
        try {
            const structure = await analyzeBookStructure(context);
            const newItem: LibraryItem = {
                book: structure,
                fileContext: context,
                uploadDate: Date.now()
            };
            setLibrary(prev => [newItem, ...prev]);
            setActiveBookId(structure.id);
            if (structure.chapters.length > 0) setActiveChapterId(structure.chapters[0].id);
            setView(AppView.DASHBOARD);
            setShowLibraryList(false);
        } catch (err: any) {
            console.error("Analysis Error:", err);
            setError("Decoding failed. " + (err.message || "The file might be too complex or the model is busy."));
        } finally {
            setIsProcessing(false);
        }
    };

    if (isEpub) {
       try {
         const textContent = await processEpub(file);
         await finalizeUpload({
            content: textContent,
            mimeType: 'text/plain',
            isText: true
         });
       } catch (err: any) {
         setError(err.message || "Failed to process EPUB.");
         setIsProcessing(false);
       }
       return;
    }

    reader.onload = async (e) => {
      let context: FileContext;
      if (isTextBased) {
          let content = e.target?.result as string;
          if (content.length > 2000000) content = content.substring(0, 2000000) + "... [Truncated]";
          context = { content, mimeType: 'text/plain', isText: true };
      } else {
          const rawBase64 = (e.target?.result as string).split(',')[1];
          // Strip newlines and whitespace which are common in base64 output and break API calls
          const cleanBase64 = rawBase64.replace(/[\r\n\s]+/g, '');
          context = { content: cleanBase64, mimeType: 'application/pdf', isText: false };
      }
      await finalizeUpload(context);
    };

    if (isTextBased) reader.readAsText(file);
    else reader.readAsDataURL(file);
  };

  const toggleBookmark = (chapterId: number) => {
    if (!activeBookId) return;
    setLibrary(prev => prev.map(item => {
        if (item.book.id === activeBookId) {
            const bookmarks = item.book.bookmarks || [];
            const isBookmarked = bookmarks.includes(chapterId);
            const newBookmarks = isBookmarked 
                ? bookmarks.filter(id => id !== chapterId)
                : [...bookmarks, chapterId];
            return { ...item, book: { ...item.book, bookmarks: newBookmarks } };
        }
        return item;
    }));
  };

  const renderContent = () => {
    if (activeTab === Tab.NOTEBOOK) {
        return (
            <Notebook 
                items={notebook} 
                onDelete={handleDeleteNotebookItem} 
                onBulkDelete={handleBulkDeleteNotebookItems} 
                onUpdateComment={handleUpdateNotebookComment} 
                onBatchUpdateDefinitions={handleBatchUpdateDefinitions}
                settings={settings} 
            />
        );
    }

    if (!activeChapter || !activeFileContext) return null;

    let content;
    switch (activeTab) {
      case Tab.AUDIOBOOK:
        content = <AudioBook chapter={activeChapter} fileContext={activeFileContext} settings={settings} onSettingsUpdate={setSettings} />;
        break;
      case Tab.PODCAST:
        content = <PodcastPlayer chapter={activeChapter} fileContext={activeFileContext} settings={settings} />;
        break;
      case Tab.CONCEPTS:
        content = <Visualizer chapter={activeChapter} fileContext={activeFileContext} />;
        break;
      case Tab.ANIMATION:
        content = <VideoSummary chapter={activeChapter} fileContext={activeFileContext} />;
        break;
      default:
        content = null;
    }

    return (
      <div key={`${activeBookId}-${activeChapter.id}-${activeTab}`} className="h-full animate-fade-in">
        {content}
      </div>
    );
  };

  if (view === AppView.UPLOAD) {
    return (
      <div className="min-h-screen bg-[#020202] bg-grid flex flex-col items-center justify-center p-6 relative overflow-hidden font-tech text-left">
        <div className="absolute top-8 left-8 w-24 h-24 border-l border-t border-zinc-800 rounded-tl-lg pointer-events-none"></div>
        <div className="absolute bottom-8 right-8 w-24 h-24 border-r border-b border-zinc-800 rounded-br-lg pointer-events-none"></div>

        <div className="z-10 max-w-lg w-full text-center space-y-12">
          <div className="space-y-2 animate-fade-in-up text-center">
             <div className="flex items-center justify-center gap-2 mb-4">
                <Terminal size={32} className="text-[#00f3ff]" />
             </div>
            <h1 className="text-7xl font-bold tracking-tighter text-white drop-shadow-[0_0_25px_rgba(0,243,255,0.3)]">
              Decod<span className="text-[#00f3ff]">Ebook</span>
            </h1>
            <p className="text-zinc-500 tracking-[0.2em] text-xs uppercase">
              V.4.2 // Neural Text Decoding Interface
            </p>
          </div>

          <div className="relative group animate-fade-in-up hud-border bg-[#050505] p-10 transition-all duration-500 hover:shadow-[0_0_30px_rgba(0,243,255,0.1)]" style={{ animationDelay: '0.1s' }}>
              {isProcessing ? (
                <Loader text="DECODING_SOURCE..." />
              ) : (
                <div className="relative flex flex-col items-center justify-center space-y-8">
                  <div className="relative">
                    <div className="w-32 h-32 bg-[#0a0a0c] border border-zinc-800 rounded-full flex items-center justify-center group-hover:border-[#00f3ff] transition-all duration-500">
                        <Upload className="w-12 h-12 text-zinc-600 group-hover:text-[#00f3ff] transition-colors" />
                    </div>
                    <div className="absolute -inset-2 border border-dashed border-zinc-800 rounded-full animate-spin-slow pointer-events-none group-hover:border-[#00f3ff]/30"></div>
                  </div>
                  <div className="space-y-2 text-center">
                    <p className="text-[#00f3ff] font-bold uppercase tracking-widest text-sm animate-pulse">Initialize Upload</p>
                    <p className="text-[10px] text-zinc-600 font-mono">SUPPORTED PROTOCOLS: PDF / EPUB / TXT / MD</p>
                  </div>
                  <input 
                    type="file" 
                    accept=".pdf,.txt,.md,.html,.xml,.epub"
                    onChange={handleFileUpload}
                    className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  />
                </div>
              )}
          </div>

          {library.length > 0 && (
             <button 
                onClick={() => setView(AppView.DASHBOARD)}
                className="text-zinc-500 hover:text-[#00f3ff] text-xs font-mono uppercase tracking-widest transition-colors flex items-center gap-2 mx-auto border border-transparent hover:border-[#00f3ff]/30 px-4 py-2 rounded-sm"
             >
                <LibraryIcon size={14} />
                Access_Data_Bank [{library.length}]
             </button>
          )}
          {error && <p className="text-[#ff003c] text-xs font-mono border border-[#ff003c]/30 p-2 bg-[#ff003c]/5">{error}</p>}
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-[#020202] bg-grid text-zinc-300 overflow-hidden font-sans relative text-left">
      <GlobalContextLayer onAddToNotebook={handleAddToNotebook} activeLanguage={settings.targetLanguage} />
      <AIAssistant 
        fileContext={activeFileContext} 
        bookTitle={activeBook?.title} 
        bookId={activeBook?.id} 
      />
      <SettingsModal 
        isOpen={isSettingsOpen} 
        onClose={() => setIsSettingsOpen(false)}
        settings={settings}
        onUpdate={setSettings}
      />

      <aside 
        className={`${isSidebarOpen ? 'w-80' : 'w-0'} bg-[#050505] flex flex-col overflow-hidden relative z-20 transition-all duration-300 border-r border-zinc-900`}
      >
        <div className="p-4 border-b border-zinc-900 shrink-0 bg-black/80 backdrop-blur-sm relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-[1px] bg-[#00f3ff] opacity-20"></div>
            <div className="flex items-center justify-between mb-6">
                <div className="flex items-center gap-2">
                    <Cpu size={16} className="text-[#00f3ff]" />
                    <span className="text-xs font-tech font-bold text-white tracking-[0.2em]">DECOD.EBOOK</span>
                </div>
                <button 
                    onClick={() => setView(AppView.UPLOAD)} 
                    className="p-1.5 rounded-sm hover:bg-zinc-900 text-zinc-600 hover:text-[#00f3ff] transition-colors"
                    title="Upload New"
                >
                    <Upload size={14} />
                </button>
            </div>
            {!showLibraryList && activeBook && (
                <div className="mt-4 p-3 border border-zinc-800 bg-zinc-900/20 rounded-sm relative group cursor-default">
                    <div className="absolute top-0 right-0 w-2 h-2 border-t border-r border-[#00f3ff]"></div>
                    <div className="absolute bottom-0 left-0 w-2 h-2 border-b border-l border-[#00f3ff]"></div>
                    <h1 className="font-bold text-xs text-white truncate leading-tight mb-1 font-tech uppercase tracking-wide">{activeBook.title}</h1>
                    <p className="text-[9px] text-zinc-500 truncate font-mono uppercase">{activeBook.author}</p>
                    <div className="mt-2 text-[9px] text-[#00f3ff] font-mono flex items-center gap-1">
                        <Activity size={10} /> SYS.ACTIVE
                    </div>
                </div>
            )}
        </div>
        <div className="flex-1 overflow-y-auto p-0 custom-scrollbar">
          {showLibraryList ? (
             <div className="flex flex-col animate-fade-in">
                {library.map(item => (
                    <button
                        key={item.book.id}
                        onClick={() => {
                            setActiveBookId(item.book.id);
                            if(item.book.chapters.length > 0) setActiveChapterId(item.book.chapters[0].id);
                            setShowLibraryList(false);
                        }}
                        className={`w-full flex items-center gap-3 p-4 border-b border-zinc-900 transition-all group ${
                            activeBookId === item.book.id 
                            ? 'bg-[#00f3ff]/5' 
                            : 'hover:bg-zinc-900'
                        }`}
                    >
                        <div className={`w-1 h-8 ${activeBookId === item.book.id ? 'bg-[#00f3ff]' : 'bg-zinc-800'}`}></div>
                        <div className="text-left min-w-0">
                            <h4 className={`text-[10px] font-bold truncate font-tech uppercase tracking-wide ${activeBookId === item.book.id ? 'text-[#00f3ff]' : 'text-zinc-400'}`}>
                                {item.book.title}
                            </h4>
                            <p className="text-[9px] text-zinc-600 truncate font-mono">{item.book.chapters.length} DATA_BLOCKS</p>
                        </div>
                    </button>
                ))}
             </div>
          ) : (
             <div className="py-2 animate-fade-in">
                {activeBook?.chapters.map((chapter, idx) => {
                    const isBookmarked = activeBook.bookmarks?.includes(chapter.id);
                    return (
                        <div key={chapter.id} className="relative group flex items-center justify-between px-4 py-2 hover:bg-zinc-900/50">
                            <button
                                onClick={() => setActiveChapterId(chapter.id)}
                                className={`flex-1 text-left flex items-center gap-3 border-l-2 py-1 transition-all min-w-0 pr-2 ${
                                    activeChapterId === chapter.id 
                                    ? 'border-[#00f3ff]' 
                                    : 'border-transparent'
                                }`}
                            >
                                <span className={`text-[9px] font-mono w-6 text-right shrink-0 ${activeChapterId === chapter.id ? 'text-[#00f3ff]' : 'text-zinc-700'}`}>
                                    {String(idx + 1).padStart(2, '0')}
                                </span>
                                <div className="min-w-0 flex-1 text-left">
                                    <p className={`font-medium truncate font-tech uppercase tracking-tight text-xs ${activeChapterId === chapter.id ? 'text-white' : 'text-zinc-500'}`}>
                                        {chapter.title}
                                    </p>
                                </div>
                            </button>
                            <button 
                                onClick={(e) => { e.stopPropagation(); toggleBookmark(chapter.id); }}
                                className={`p-1.5 transition-colors shrink-0 ${isBookmarked ? 'text-amber-400' : 'text-zinc-800 hover:text-zinc-500'}`}
                                title={isBookmarked ? "Remove Bookmark" : "Add Bookmark"}
                            >
                                <Tag size={12} fill={isBookmarked ? "currentColor" : "none"} />
                            </button>
                        </div>
                    );
                })}
             </div>
          )}
        </div>
        <div className="p-0 border-t border-zinc-900 bg-black flex flex-col shrink-0">
          <button 
            onClick={() => setShowLibraryList(!showLibraryList)}
            className={`w-full flex items-center justify-between p-4 transition-all text-[10px] font-bold font-tech uppercase tracking-widest border-b border-zinc-900/30 ${
                showLibraryList ? 'text-[#00f3ff] bg-[#00f3ff]/5' : 'text-zinc-500 hover:bg-zinc-900 hover:text-[#00f3ff]'
            }`}
          >
             <div className="flex items-center gap-3">
                <Database size={14} />
                <span>{showLibraryList ? "SESSION_DATA" : "DATA_BANKS"}</span>
             </div>
             <span className={`text-[8px] animate-pulse ${showLibraryList ? 'text-[#00f3ff]' : 'text-zinc-700'}`}>●</span>
          </button>
          <button 
            onClick={() => setIsSettingsOpen(true)}
            className="w-full flex items-center gap-3 p-4 hover:bg-zinc-900 text-zinc-500 hover:text-[#00f3ff] transition-colors text-[10px] font-bold font-tech uppercase tracking-widest"
          >
            <SettingsIcon size={14} />
            <span>SYS_CONFIG</span>
          </button>
        </div>
      </aside>

      <main className="flex-1 flex flex-col min-w-0 relative bg-transparent z-10 text-left">
        <header className="h-14 border-b border-zinc-900 flex items-center justify-between px-4 bg-black/90 backdrop-blur-md sticky top-0 z-30 shrink-0">
          <div className="flex items-center gap-4">
            <button onClick={() => setSidebarOpen(!isSidebarOpen)} className="text-zinc-500 hover:text-[#00f3ff] transition-colors">
              {isSidebarOpen ? <X size={18} /> : <Menu size={18} />}
            </button>
            <div className="h-4 w-[1px] bg-zinc-800 mx-1"></div>
            {activeChapterId ? (
                <div className="flex items-center gap-2">
                    <span className="text-[9px] font-mono text-zinc-600 bg-zinc-900 border border-zinc-800 px-1.5 py-0.5">
                        SEC.{String(activeChapterId || 0).padStart(2, '0')}
                    </span>
                    <ChevronRight size={12} className="text-zinc-700" />
                    <span className="text-xs font-bold text-[#00f3ff] font-tech tracking-wide truncate max-w-[200px]">
                        {activeChapter?.title.toUpperCase()}
                    </span>
                </div>
            ) : (
                <span className="text-xs font-tech text-zinc-500 tracking-widest">AWAITING_INPUT</span>
            )}
          </div>

          <div className="flex items-center bg-zinc-950 border border-zinc-900 p-0.5 rounded-sm">
            {[
              { id: Tab.AUDIOBOOK, icon: Headphones, label: "VOICE_SYNTH" },
              { id: Tab.PODCAST, icon: Mic2, label: "NET_CAST" },
              { id: Tab.CONCEPTS, icon: ImageIcon, label: "VISUAL_CORE" },
              { id: Tab.ANIMATION, icon: Film, label: "CINE_RENDER" },
              { id: Tab.NOTEBOOK, icon: NotebookIcon, label: "MEM_LOG" },
            ].map((tab) => (
              <button
                key={tab.id}
                onClick={() => setActiveTab(tab.id as Tab)}
                className={`flex items-center justify-center gap-2 w-[120px] py-1.5 transition-all text-[9px] font-bold uppercase tracking-wider font-tech ${
                  activeTab === tab.id 
                    ? 'bg-[#00f3ff]/10 text-[#00f3ff] shadow-[0_0_10px_rgba(0,243,255,0.1)]'
                    : 'text-zinc-600 hover:text-zinc-300 hover:bg-zinc-900'
                }`}
              >
                <tab.icon size={12} className={activeTab === tab.id ? 'text-[#00f3ff]' : ''} />
                <span className="hidden xl:inline">{tab.label}</span>
              </button>
            ))}
          </div>
        </header>

        <div className="flex-1 p-0 overflow-hidden relative">
          <div className="h-full w-full p-2 overflow-y-auto custom-scrollbar">
             {renderContent()}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { NotebookItem, AppSettings } from '../types';
import { Trash2, Quote, Book, Clock, ImageDown, Volume2, X as XIcon, Play, Zap, Notebook as NotebookIcon, ChevronDown, Settings2, Type, Loader2, AlertCircle, ChevronUp, Languages, ChevronLeft, ChevronRight, ArrowUpDown } from 'lucide-react';
import { generateSpeech, getQuickDefinition, translateText } from '../services/gemini';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  onBatchUpdateDefinitions?: (updates: Record<string, string>) => void;
  settings: AppSettings;
}

type FilterType = 'all' | 'word' | 'phrase' | 'sentence';
type SortOrder = 'newest' | 'oldest' | 'az' | 'za';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, onBatchUpdateDefinitions, settings }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('all');
  const [sortOrder, setSortOrder] = useState<SortOrder>('newest');

  const [isFlashcardMode, setIsFlashcardMode] = useState(false);
  const [currentFlashcardIndex, setCurrentFlashcardIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isPreparingCards, setIsPreparingCards] = useState(false);
  const [fetchingIds, setFetchingIds] = useState<Set<string>>(new Set());

  // Local cache for definitions and translations during the current study session
  const [sessionDefinitions, setSessionDefinitions] = useState<Record<string, string>>({});
  const [sessionTranslations, setSessionTranslations] = useState<Record<string, string>>({});
  const [showTranslatedCard, setShowTranslatedCard] = useState(false);
  const [isTranslatingCard, setIsTranslatingCard] = useState(false);

  const filteredItems = useMemo(() => {
      let result = activeFilter === 'all' 
        ? [...items] 
        : items.filter(item => item.type === activeFilter);

      switch (sortOrder) {
          case 'newest':
              result.sort((a, b) => b.timestamp - a.timestamp);
              break;
          case 'oldest':
              result.sort((a, b) => a.timestamp - b.timestamp);
              break;
          case 'az':
              result.sort((a, b) => a.text.localeCompare(b.text));
              break;
          case 'za':
              result.sort((a, b) => b.text.localeCompare(a.text));
              break;
      }
      return result;
  }, [items, activeFilter, sortOrder]);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.width = 800;
      canvas.height = 800;
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) { ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke(); }
      for(let i=0; i < canvas.height; i+=40) { ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke(); }
      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      let y = margin + 40;
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;
      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;
      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';
      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };
      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }
      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);
      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) { ctx.fillText(lines[i], margin, y); y += lineHeight; }
      y += 30;
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }
      if (item.comment) {
          ctx.fillStyle = '#f59e0b'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> USER_ANNOTATION:", margin, y); y += 20;
          ctx.fillStyle = '#b45309'; ctx.font = 'italic 14px "Courier New", monospace';
          const commentWords = item.comment.split(' ');
          let commentLine = '';
          for(let n = 0; n < commentWords.length; n++) {
            const testLine = commentLine + commentWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(commentLine, margin, y); commentLine = commentWords[n] + ' '; y += 18;
            } else { commentLine = testLine; }
         }
         ctx.fillText(commentLine, margin, y); y += 35;
      }
      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);
      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const startFlashcards = () => {
      if (filteredItems.length === 0) return;
      setCurrentFlashcardIndex(0);
      setIsFlipped(false);
      setShowTranslatedCard(false);
      setIsFlashcardMode(true);
      setSessionDefinitions({});
      setSessionTranslations({});
  };

  const currentStudyItem = filteredItems[currentFlashcardIndex];

  // Logic for switching between original language definition and translation
  const originalDef = (currentStudyItem?.id && sessionDefinitions[currentStudyItem.id]) || currentStudyItem?.definition;
  const translatedDef = currentStudyItem?.id ? sessionTranslations[currentStudyItem.id] : null;
  const activeDefinition = showTranslatedCard ? translatedDef : originalDef;
  const isCurrentItemLoading = currentStudyItem?.id && fetchingIds.has(currentStudyItem.id);

  useEffect(() => {
    if (isFlashcardMode && currentStudyItem && !currentStudyItem.definition && !sessionDefinitions[currentStudyItem.id] && !fetchingIds.has(currentStudyItem.id)) {
        const fetchDef = async () => {
            const itemId = currentStudyItem.id;
            setFetchingIds(prev => new Set(prev).add(itemId));
            try {
                // Always fetch in source language first for Flashcards
                // Note: We only update session cache, NOT the database (removed onBatchUpdateDefinitions)
                const def = await getQuickDefinition(currentStudyItem.text, "the same language as the text");
                setSessionDefinitions(prev => ({ ...prev, [itemId]: def }));
            } catch (e: any) {
                console.error("Failed to pre-fetch definition:", e);
                setSessionDefinitions(prev => ({ ...prev, [itemId]: "ERR_DECODE: Signal interference." }));
            } finally {
                setFetchingIds(prev => {
                    const next = new Set(prev);
                    next.delete(itemId);
                    return next;
                });
            }
        };
        fetchDef();
    }
  }, [isFlashcardMode, currentFlashcardIndex, currentStudyItem]);

  const handleTranslateFlashcard = async (e: React.MouseEvent) => {
      e.stopPropagation();
      if (!currentStudyItem || isTranslatingCard) return;

      if (showTranslatedCard) {
          setShowTranslatedCard(false);
          return;
      }

      if (sessionTranslations[currentStudyItem.id]) {
          setShowTranslatedCard(true);
          return;
      }

      const textToTranslate = originalDef;
      if (!textToTranslate) return;

      setIsTranslatingCard(true);
      try {
          const targetLang = settings.targetLanguage === 'Original' ? 'English' : settings.targetLanguage;
          const trans = await translateText(textToTranslate, targetLang);
          setSessionTranslations(prev => ({ ...prev, [currentStudyItem.id]: trans }));
          setShowTranslatedCard(true);
      } catch (e) {
          console.error("Flashcard translation failed:", e);
      } finally {
          setIsTranslatingCard(false);
      }
  };

  const handleFlip = (item: NotebookItem) => {
      setIsFlipped(!isFlipped);
  };

  const formatAnalysisText = (text: string) => {
      if (!text) return null;
      return text.split('\n').map((line, i) => {
          const trimmed = line.trim();
          if (!trimmed) return <div key={i} className="h-2" />;
          const parts = trimmed.split(/(\*\*.*?\*\*)/g);
          return (
              <p key={i} className="mb-2">
                  {parts.map((part, pi) => {
                      if (part.startsWith('**') && part.endsWith('**')) {
                          return <span key={pi} className="text-[#ff003c] font-bold">{part.slice(2, -2)}</span>;
                      }
                      return part;
                  })}
              </p>
          );
      });
  };

  const renderFlashcards = () => {
    if (!currentStudyItem) return null;
    return (
        <div className="flex flex-col items-center justify-center h-full animate-fade-in relative p-4">
             {/* Progress Bar */}
             <div className="absolute top-4 left-0 w-full px-12 flex items-center justify-between text-xs font-mono text-zinc-500">
                 <span>CARD {currentFlashcardIndex + 1} / {filteredItems.length}</span>
                 <div className="flex-1 mx-4 h-1 bg-zinc-900 rounded-full overflow-hidden">
                     <div className="h-full bg-[#00f3ff]" style={{ width: `${((currentFlashcardIndex + 1) / filteredItems.length) * 100}%` }}></div>
                 </div>
                 <span>{((currentFlashcardIndex + 1) / filteredItems.length * 100).toFixed(0)}%</span>
             </div>

             <div className="relative w-full max-w-2xl aspect-[3/2] perspective-1000 group cursor-pointer" onClick={() => handleFlip(currentStudyItem)}>
                 <div className={`w-full h-full relative transition-all duration-700 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>
                     {/* Front Side */}
                     <div className="absolute inset-0 backface-hidden bg-[#0a0a0c] border border-zinc-800 rounded-xl p-10 flex flex-col items-center justify-center shadow-2xl group-hover:border-[#00f3ff]/50 transition-colors">
                         <div className="absolute top-6 left-6 flex items-center gap-2">
                             <div className={`px-2 py-1 rounded-sm text-[9px] font-bold uppercase tracking-wider border ${currentStudyItem.type === 'word' ? 'bg-emerald-900/30 border-emerald-500/30 text-emerald-400' : currentStudyItem.type === 'phrase' ? 'bg-amber-900/30 border-amber-500/30 text-amber-400' : 'bg-cyan-900/30 border-cyan-500/30 text-cyan-400'}`}>
                                 {currentStudyItem.type}
                             </div>
                         </div>
                         <div className="absolute top-6 right-6">
                            <button onClick={(e) => { e.stopPropagation(); playPronunciation(currentStudyItem.id, currentStudyItem.text); }} className="p-2 text-zinc-500 hover:text-[#00f3ff] transition-colors bg-zinc-900/50 rounded-full">
                                <Volume2 size={20} />
                            </button>
                         </div>

                         <h2 className="text-4xl font-bold text-white text-center font-serif leading-tight">{currentStudyItem.text}</h2>

                         {currentStudyItem.bookTitle && (
                             <p className="absolute bottom-6 text-zinc-600 text-xs font-mono uppercase tracking-widest">{currentStudyItem.bookTitle.substring(0, 30)}</p>
                         )}
                         <div className="absolute bottom-6 right-6 text-[#00f3ff] text-[10px] animate-pulse font-mono">CLICK_TO_REVEAL_DATA</div>
                     </div>

                     {/* Back Side */}
                     <div className="absolute inset-0 backface-hidden rotate-y-180 bg-[#050505] border border-[#00f3ff]/30 rounded-xl p-10 flex flex-col shadow-[0_0_30px_rgba(0,243,255,0.1)] relative">
                         <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#00f3ff] to-transparent"></div>

                         <div className="flex items-center justify-between mb-6">
                             <h3 className="text-[#00f3ff] font-bold font-mono text-sm uppercase tracking-wider flex items-center gap-2">
                                <BookOpen size={16} />
                                ANALYSIS_MATRIX
                             </h3>
                             <button 
                                onClick={handleTranslateFlashcard}
                                className={`text-xs flex items-center gap-2 px-2 py-1 rounded-sm border transition-all ${showTranslatedCard ? 'bg-emerald-900/30 border-emerald-500/50 text-emerald-400' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:text-[#00f3ff]'}`}
                             >
                                 {isTranslatingCard ? <Loader2 size={12} className="animate-spin" /> : <Languages size={12} />}
                                 {showTranslatedCard ? "SHOW_SOURCE" : "TRANSLATE"}
                             </button>
                         </div>

                         <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 relative">
                             {isCurrentItemLoading ? (
                                 <div className="absolute inset-0 flex items-center justify-center flex-col gap-3 text-zinc-500">
                                     <Loader2 size={32} className="animate-spin text-[#00f3ff]" />
                                     <span className="text-xs font-mono animate-pulse">DECODING_NEURAL_PATHWAYS...</span>
                                 </div>
                             ) : (
                                 <div className="text-sm leading-relaxed text-zinc-300 font-medium">
                                     {formatAnalysisText(activeDefinition || "No definition data available.")}
                                 </div>
                             )}
                         </div>

                         {currentStudyItem.comment && (
                             <div className="mt-4 pt-4 border-t border-zinc-900">
                                 <div className="flex items-center gap-2 text-amber-500 text-xs font-bold mb-1 uppercase font-mono">
                                     <Quote size={12} /> USER_NOTE
                                 </div>
                                 <p className="text-zinc-500 text-xs italic pl-4 border-l border-amber-500/20">{currentStudyItem.comment}</p>
                             </div>
                         )}
                     </div>
                 </div>
             </div>

             {/* Navigation */}
             <div className="mt-8 flex items-center gap-8">
                 <button 
                    onClick={() => { setIsFlipped(false); setCurrentFlashcardIndex(prev => Math.max(0, prev - 1)); }}
                    disabled={currentFlashcardIndex === 0}
                    className="p-3 rounded-full border border-zinc-800 text-zinc-500 hover:text-[#00f3ff] hover:border-[#00f3ff] transition-all disabled:opacity-30 disabled:cursor-not-allowed hover:scale-110"
                 >
                     <ChevronLeft size={24} />
                 </button>
                 <button 
                    onClick={() => { setIsFlipped(false); setCurrentFlashcardIndex(prev => Math.min(filteredItems.length - 1, prev + 1)); }}
                    disabled={currentFlashcardIndex === filteredItems.length - 1}
                    className="p-3 rounded-full border border-zinc-800 text-zinc-500 hover:text-[#00f3ff] hover:border-[#00f3ff] transition-all disabled:opacity-30 disabled:cursor-not-allowed hover:scale-110"
                 >
                     <ChevronRight size={24} />
                 </button>
             </div>
        </div>
    );
  };

  const renderList = () => (
    <div className="h-full overflow-y-auto custom-scrollbar p-1">
        {filteredItems.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-full text-zinc-600 space-y-4 opacity-50">
                <NotebookIcon size={48} />
                <p className="font-mono text-xs uppercase tracking-widest">NO_DATA_LOGGED</p>
            </div>
        ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 pb-20">
                {filteredItems.map(item => (
                    <div key={item.id} className="group relative bg-[#0a0a0c] border border-zinc-800 p-5 rounded-lg hover:border-[#00f3ff]/50 transition-all duration-300 hover:shadow-[0_0_20px_rgba(0,0,0,0.5)] flex flex-col">
                        <div className="flex justify-between items-start mb-3">
                            <div className={`px-1.5 py-0.5 rounded-sm text-[9px] font-bold uppercase tracking-wider border ${
                                item.type === 'word' ? 'bg-emerald-900/20 border-emerald-500/20 text-emerald-500' :
                                item.type === 'phrase' ? 'bg-amber-900/20 border-amber-500/20 text-amber-500' :
                                'bg-cyan-900/20 border-cyan-500/20 text-cyan-500'
                            }`}>
                                {item.type}
                            </div>
                            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                <button onClick={() => generateStickyNote(item)} className="p-1.5 text-zinc-500 hover:text-[#00f3ff] transition-colors rounded hover:bg-zinc-900" title="Export Sticky"><ImageDown size={14} /></button>
                                <button onClick={() => playPronunciation(item.id, item.text)} className={`p-1.5 text-zinc-500 hover:text-[#00f3ff] transition-colors rounded hover:bg-zinc-900 ${playingId === item.id ? 'text-[#00f3ff] animate-pulse' : ''}`} title="Pronounce"><Volume2 size={14} /></button>
                                <button onClick={() => onDelete(item.id)} className="p-1.5 text-zinc-500 hover:text-[#ff003c] transition-colors rounded hover:bg-zinc-900" title="Delete"><Trash2 size={14} /></button>
                            </div>
                        </div>

                        <h3 className="text-lg font-bold text-white mb-2 leading-tight font-serif break-words">{item.text}</h3>

                        {item.definition && (
                            <div className="mb-3 pl-3 border-l-2 border-zinc-800 text-xs text-zinc-400 leading-relaxed line-clamp-4">
                                {item.definition.split('\n')[0]}
                            </div>
                        )}

                        <div className="mt-auto pt-3 border-t border-zinc-900 flex items-center justify-between text-[10px] text-zinc-600 font-mono">
                            <div className="flex items-center gap-2">
                                <Clock size={10} />
                                <span>{new Date(item.timestamp).toLocaleDateString()}</span>
                            </div>
                            {item.bookTitle && (
                                <div className="flex items-center gap-1 max-w-[120px]">
                                    <Book size={10} />
                                    <span className="truncate" title={item.bookTitle}>{item.bookTitle}</span>
                                </div>
                            )}
                        </div>
                    </div>
                ))}
            </div>
        )}
    </div>
  );

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left relative" style={fontStyle}>
       <style>{`
          .perspective-1000 { perspective: 1000px; -webkit-perspective: 1000px; } 
          .backface-hidden { backface-visibility: hidden; -webkit-backface-visibility: hidden; z-index: 2; } 
          .rotate-y-180 { transform: rotateY(180deg); -webkit-transform: rotateY(180deg); } 
          .transform-style-3d { transform-style: preserve-3d; -webkit-transform-style: preserve-3d; }
          .custom-scrollbar-visible::-webkit-scrollbar { width: 6px; }
          .custom-scrollbar-visible::-webkit-scrollbar-track { background: rgba(0,0,0,0.3); border-radius: 3px; }
          .custom-scrollbar-visible::-webkit-scrollbar-thumb { background: #ff003c; border-radius: 3px; box-shadow: 0 0 10px rgba(255,0,60,0.5); }
       `}</style>

       {/* Toolbar */}
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-nowrap gap-2 z-10 transition-all duration-300">
           <div className="flex items-center gap-4 flex-1">
               <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs shrink-0">
                   <NotebookIcon size={18} className="text-[#00f3ff]" />
                   <span>Mem_Log</span>
               </div>

               {/* Divider */}
               <div className="w-[1px] h-4 bg-zinc-800"></div>

               {/* Filters - Use visibility/width to maintain layout stability during flashcard mode */}
               {/* When isFlashcardMode is true, we hide these but keep the structure to avoid jumping, or we animate them out gracefully */}
               {/* Using opacity-0 + pointer-events-none keeps them taking up space if we want exact layout match, but shrinking them looks cleaner. */}
               {/* To satisfy "width of top controller changed", we ensure the CONTAINER width is fixed (w-full on parent) and flex behavior is stable. */}
               <div className={`flex items-center gap-1 overflow-hidden transition-all duration-300 ease-in-out ${isFlashcardMode ? 'opacity-0 pointer-events-none max-w-0' : 'opacity-100 max-w-[400px]'}`}>
                   {(['all', 'word', 'phrase', 'sentence'] as const).map(f => (
                       <button 
                          key={f}
                          onClick={() => setActiveFilter(f)}
                          className={`px-3 py-1 rounded-sm text-[10px] font-bold uppercase tracking-wider transition-all ${activeFilter === f ? 'bg-[#00f3ff]/20 text-[#00f3ff] border border-[#00f3ff]/30' : 'text-zinc-500 hover:text-zinc-300'}`}
                       >
                          {f}
                       </button>
                   ))}
               </div>
           </div>

           <div className="flex items-center gap-3 shrink-0">
               {/* Sort - Hide in flashcard mode */}
               <div className={`flex items-center gap-2 mr-2 transition-all duration-300 ${isFlashcardMode ? 'opacity-0 pointer-events-none w-0 overflow-hidden' : 'opacity-100 w-auto'}`}>
                   <span className="text-[10px] text-zinc-600 font-mono uppercase whitespace-nowrap">Sort:</span>
                   <select 
                      value={sortOrder}
                      onChange={(e) => setSortOrder(e.target.value as SortOrder)}
                      className="bg-[#050505] border border-zinc-800 text-[10px] text-[#00f3ff] font-mono uppercase rounded-sm px-2 py-1 outline-none focus:border-[#00f3ff]"
                   >
                       <option value="newest">Time (New)</option>
                       <option value="oldest">Time (Old)</option>
                       <option value="az">A-Z</option>
                       <option value="za">Z-A</option>
                   </select>
               </div>

               <button 
                  onClick={isFlashcardMode ? () => setIsFlashcardMode(false) : startFlashcards}
                  disabled={filteredItems.length === 0}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[150px] justify-center ${isFlashcardMode ? 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'} ${filteredItems.length === 0 ? 'opacity-50 cursor-not-allowed' : ''}`}
               >
                   {isFlashcardMode ? <XIcon size={14} /> : <Zap size={14} fill="currentColor" />}
                   {isFlashcardMode ? "End_Session" : "Neural_Flashcards"}
               </button>
           </div>
       </div>

       {/* Content Area */}
       <div className="flex-1 min-h-0 relative">
          {isFlashcardMode ? renderFlashcards() : renderList()}
       </div>

    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { NotebookItem, AppSettings } from '../types';
import { Trash2, Quote, Book, BookOpen, Clock, ImageDown, Volume2, X as XIcon, Play, Zap, Notebook as NotebookIcon, ChevronDown, Settings2, Type, Loader2, AlertCircle, ChevronUp, Languages, ChevronLeft, ChevronRight, ArrowUpDown } from 'lucide-react';
import { generateSpeech, getQuickDefinition, translateText } from '../services/gemini';

interface Props {
  items: NotebookItem[];
  onDelete: (id: string) => void;
  onBulkDelete: (ids: string[]) => void;
  onUpdateComment: (id: string, comment: string) => void;
  onBatchUpdateDefinitions?: (updates: Record<string, string>) => void;
  settings: AppSettings;
}

type FilterType = 'all' | 'word' | 'phrase' | 'sentence';
type SortOrder = 'newest' | 'oldest' | 'az' | 'za';

export const Notebook: React.FC<Props> = ({ items, onDelete, onBulkDelete, onUpdateComment, onBatchUpdateDefinitions, settings }) => {
  const fontStyle = { fontFamily: settings.font ? `"${settings.font}", sans-serif` : 'inherit' };
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [activeFilter, setActiveFilter] = useState<FilterType>('all');
  const [sortOrder, setSortOrder] = useState<SortOrder>('newest');

  const [isFlashcardMode, setIsFlashcardMode] = useState(false);
  const [currentFlashcardIndex, setCurrentFlashcardIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [isPreparingCards, setIsPreparingCards] = useState(false);
  const [fetchingIds, setFetchingIds] = useState<Set<string>>(new Set());

  // Local cache for definitions and translations during the current study session
  const [sessionDefinitions, setSessionDefinitions] = useState<Record<string, string>>({});
  const [sessionTranslations, setSessionTranslations] = useState<Record<string, string>>({});
  const [showTranslatedCard, setShowTranslatedCard] = useState(false);
  const [isTranslatingCard, setIsTranslatingCard] = useState(false);

  const filteredItems = useMemo(() => {
      let result = activeFilter === 'all' 
        ? [...items] 
        : items.filter(item => item.type === activeFilter);

      switch (sortOrder) {
          case 'newest':
              result.sort((a, b) => b.timestamp - a.timestamp);
              break;
          case 'oldest':
              result.sort((a, b) => a.timestamp - b.timestamp);
              break;
          case 'az':
              result.sort((a, b) => a.text.localeCompare(b.text));
              break;
          case 'za':
              result.sort((a, b) => b.text.localeCompare(a.text));
              break;
      }
      return result;
  }, [items, activeFilter, sortOrder]);

  const pcmToWav = (base64Pcm: string) => {
    const binaryString = atob(base64Pcm);
    const len = binaryString.length;
    const buffer = new ArrayBuffer(44 + len);
    const view = new DataView(buffer);
    const writeString = (v: DataView, offset: number, str: string) => {
      for (let i = 0; i < str.length; i++) v.setUint8(offset + i, str.charCodeAt(i));
    };
    writeString(view, 0, 'RIFF');
    view.setUint32(4, 36 + len, true);
    writeString(view, 8, 'WAVE');
    writeString(view, 12, 'fmt ');
    view.setUint32(16, 16, true);
    view.setUint16(20, 1, true);
    view.setUint16(22, 1, true);
    view.setUint32(24, 24000, true);
    view.setUint32(28, 48000, true);
    view.setUint16(32, 2, true);
    view.setUint16(34, 16, true);
    writeString(view, 36, 'data');
    view.setUint32(40, len, true);
    const bytes = new Uint8Array(buffer, 44);
    for (let i = 0; i < len; i++) bytes[i] = binaryString.charCodeAt(i);
    return new Blob([buffer], { type: 'audio/wav' });
  };

  const playPronunciation = async (id: string, text: string) => {
     if (playingId) return;
     setPlayingId(id);
     let audioUrl: string | null = null;
     try {
          const b64 = await generateSpeech(text, "Puck");
          if(b64) {
             const blob = pcmToWav(b64);
             audioUrl = URL.createObjectURL(blob);
             const audio = new Audio(audioUrl);
             audio.onended = () => {
                 setPlayingId(null);
                 if (audioUrl) URL.revokeObjectURL(audioUrl);
             };
             await audio.play();
          } else {
             setPlayingId(null);
          }
      } catch (e) {
          console.error("Playback failed:", e);
          setPlayingId(null);
          if (audioUrl) URL.revokeObjectURL(audioUrl);
      }
  };

  const generateStickyNote = (item: NotebookItem) => {
      const canvas = document.createElement('canvas');
      const ctx = canvas.getContext('2d');
      if (!ctx) return;
      canvas.width = 800;
      canvas.height = 800;
      ctx.fillStyle = '#050505'; 
      ctx.fillRect(0, 0, canvas.width, canvas.height);
      ctx.strokeStyle = '#1f2937';
      ctx.lineWidth = 1;
      for(let i=0; i < canvas.width; i+=40) { ctx.beginPath(); ctx.moveTo(i, 0); ctx.lineTo(i, canvas.height); ctx.stroke(); }
      for(let i=0; i < canvas.height; i+=40) { ctx.beginPath(); ctx.moveTo(0, i); ctx.lineTo(canvas.width, i); ctx.stroke(); }
      const margin = 50;
      const contentWidth = canvas.width - (margin * 2);
      ctx.fillStyle = '#00f3ff';
      const cornerSize = 8;
      ctx.fillRect(margin, margin, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, margin, cornerSize, cornerSize);
      ctx.fillRect(margin, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      ctx.fillRect(canvas.width - margin - cornerSize, canvas.height - margin - cornerSize, cornerSize, cornerSize);
      let y = margin + 40;
      ctx.fillStyle = '#ff003c';
      ctx.font = 'bold 16px "Courier New", monospace';
      ctx.textAlign = 'left';
      ctx.fillText(`// LOG_DATE: ${new Date(item.timestamp).toISOString().split('T')[0]}`, margin, y);
      y += 25;
      if (item.bookTitle) {
          ctx.fillStyle = '#00f3ff';
          ctx.font = 'bold 20px "Courier New", monospace';
          const authorText = item.bookAuthor ? ` | ${item.bookAuthor}` : '';
          ctx.fillText(`BOOK: ${item.bookTitle.toUpperCase().substring(0, 20)}${authorText.substring(0, 15)}`, margin, y);
          y += 25;
      }
      ctx.strokeStyle = '#334155'; ctx.lineWidth = 1; ctx.beginPath(); ctx.moveTo(margin, y); ctx.lineTo(canvas.width - margin, y); ctx.stroke();
      y += 40;
      let fontSize = 32;
      const mainFont = settings.font ? `"${settings.font}", sans-serif` : 'Georgia';
      ctx.font = `${fontSize}px ${mainFont}`;
      const words = item.text.split(' ');
      let lines: string[] = [];
      let line = '';
      const calculateLines = () => {
         lines = []; line = '';
         for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
              lines.push(line); line = words[n] + ' ';
            } else { line = testLine; }
         }
         lines.push(line);
      };
      calculateLines();
      const maxHeight = 350;
      while (lines.length * (fontSize * 1.5) > maxHeight && fontSize > 14) {
          fontSize -= 2; ctx.font = `${fontSize}px ${mainFont}`; calculateLines();
      }
      ctx.fillStyle = '#334155'; ctx.font = `${fontSize * 3}px ${mainFont}`;
      ctx.fillText('"', margin - 20, y + fontSize);
      ctx.fillStyle = '#e2e8f0'; ctx.font = `${fontSize}px ${mainFont}`;
      const lineHeight = fontSize * 1.5;
      for (let i = 0; i < lines.length; i++) { ctx.fillText(lines[i], margin, y); y += lineHeight; }
      y += 30;
      if (item.definition) {
          ctx.fillStyle = '#22d3ee'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> ANALYSIS_OUTPUT:", margin, y); y += 20;
          ctx.fillStyle = '#94a3b8'; ctx.font = '14px "Courier New", monospace';
          const defWords = item.definition.split(' ');
          let defLine = '';
          for(let n = 0; n < defWords.length; n++) {
            const testLine = defLine + defWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(defLine, margin, y); defLine = defWords[n] + ' '; y += 18;
            } else { defLine = testLine; }
         }
         ctx.fillText(defLine, margin, y); y += 35;
      }
      if (item.comment) {
          ctx.fillStyle = '#f59e0b'; ctx.font = 'bold 14px "Courier New", monospace';
          ctx.fillText(">> USER_ANNOTATION:", margin, y); y += 20;
          ctx.fillStyle = '#b45309'; ctx.font = 'italic 14px "Courier New", monospace';
          const commentWords = item.comment.split(' ');
          let commentLine = '';
          for(let n = 0; n < commentWords.length; n++) {
            const testLine = commentLine + commentWords[n] + ' ';
            const metrics = ctx.measureText(testLine);
            if (metrics.width > contentWidth && n > 0) {
               ctx.fillText(commentLine, margin, y); commentLine = commentWords[n] + ' '; y += 18;
            } else { commentLine = testLine; }
         }
         ctx.fillText(commentLine, margin, y); y += 35;
      }
      ctx.fillStyle = '#1f2937'; ctx.font = '10px "Courier New", monospace'; ctx.textAlign = 'center';
      ctx.fillText("FLASH_NOTES // NEURAL INTERFACE CONTENT", canvas.width / 2, canvas.height - 20);
      const link = document.createElement('a');
      link.download = `flash-note-${item.id}.png`;
      link.href = canvas.toDataURL();
      link.click();
  };

  const startFlashcards = () => {
      if (filteredItems.length === 0) return;
      setCurrentFlashcardIndex(0);
      setIsFlipped(false);
      setShowTranslatedCard(false);
      setIsFlashcardMode(true);
      setSessionDefinitions({});
      setSessionTranslations({});
  };

  const currentStudyItem = filteredItems[currentFlashcardIndex];

  // Logic for switching between original language definition and translation
  const originalDef = (currentStudyItem?.id && sessionDefinitions[currentStudyItem.id]) || currentStudyItem?.definition;
  const translatedDef = currentStudyItem?.id ? sessionTranslations[currentStudyItem.id] : null;
  const activeDefinition = showTranslatedCard ? translatedDef : originalDef;
  const isCurrentItemLoading = currentStudyItem?.id && fetchingIds.has(currentStudyItem.id);

  useEffect(() => {
    if (isFlashcardMode && currentStudyItem && !currentStudyItem.definition && !sessionDefinitions[currentStudyItem.id] && !fetchingIds.has(currentStudyItem.id)) {
        const fetchDef = async () => {
            const itemId = currentStudyItem.id;
            setFetchingIds(prev => new Set(prev).add(itemId));
            try {
                // Always fetch in source language first for Flashcards
                // Note: We only update session cache, NOT the database (removed onBatchUpdateDefinitions)
                const def = await getQuickDefinition(currentStudyItem.text, "the same language as the text");
                setSessionDefinitions(prev => ({ ...prev, [itemId]: def }));
            } catch (e: any) {
                console.error("Failed to pre-fetch definition:", e);
                setSessionDefinitions(prev => ({ ...prev, [itemId]: "ERR_DECODE: Signal interference." }));
            } finally {
                setFetchingIds(prev => {
                    const next = new Set(prev);
                    next.delete(itemId);
                    return next;
                });
            }
        };
        fetchDef();
    }
  }, [isFlashcardMode, currentFlashcardIndex, currentStudyItem]);

  const handleTranslateFlashcard = async (e: React.MouseEvent) => {
      e.stopPropagation();
      if (!currentStudyItem || isTranslatingCard) return;

      if (showTranslatedCard) {
          setShowTranslatedCard(false);
          return;
      }

      if (sessionTranslations[currentStudyItem.id]) {
          setShowTranslatedCard(true);
          return;
      }

      const textToTranslate = originalDef;
      if (!textToTranslate) return;

      setIsTranslatingCard(true);
      try {
          const targetLang = settings.targetLanguage === 'Original' ? 'English' : settings.targetLanguage;
          const trans = await translateText(textToTranslate, targetLang);
          setSessionTranslations(prev => ({ ...prev, [currentStudyItem.id]: trans }));
          setShowTranslatedCard(true);
      } catch (e) {
          console.error("Flashcard translation failed:", e);
      } finally {
          setIsTranslatingCard(false);
      }
  };

  const handleFlip = (item: NotebookItem) => {
      setIsFlipped(!isFlipped);
  };

  const formatAnalysisText = (text: string) => {
      if (!text) return null;
      return text.split('\n').map((line, i) => {
          const trimmed = line.trim();
          if (!trimmed) return <div key={i} className="h-2" />;
          const parts = trimmed.split(/(\*\*.*?\*\*)/g);
          return (
              <p key={i} className="mb-2">
                  {parts.map((part, pi) => {
                      if (part.startsWith('**') && part.endsWith('**')) {
                          return <span key={pi} className="text-[#ff003c] font-bold">{part.slice(2, -2)}</span>;
                      }
                      return part;
                  })}
              </p>
          );
      });
  };

  const renderFlashcards = () => {
    if (!currentStudyItem) return null;
    return (
        <div className="flex flex-col items-center justify-center h-full animate-fade-in relative p-4">
             {/* Progress Bar */}
             <div className="absolute top-4 left-0 w-full px-12 flex items-center justify-between text-xs font-mono text-zinc-500">
                 <span>CARD {currentFlashcardIndex + 1} / {filteredItems.length}</span>
                 <div className="flex-1 mx-4 h-1 bg-zinc-900 rounded-full overflow-hidden">
                     <div className="h-full bg-[#00f3ff]" style={{ width: `${((currentFlashcardIndex + 1) / filteredItems.length) * 100}%` }}></div>
                 </div>
                 <span>{((currentFlashcardIndex + 1) / filteredItems.length * 100).toFixed(0)}%</span>
             </div>

             <div className="relative w-full max-w-2xl aspect-[3/2] perspective-1000 group cursor-pointer" onClick={() => handleFlip(currentStudyItem)}>
                 <div className={`w-full h-full relative transition-all duration-700 transform-style-3d ${isFlipped ? 'rotate-y-180' : ''}`}>
                     {/* Front Side */}
                     <div className="absolute inset-0 backface-hidden bg-[#0a0a0c] border border-zinc-800 rounded-xl p-10 flex flex-col items-center justify-center shadow-2xl group-hover:border-[#00f3ff]/50 transition-colors">
                         <div className="absolute top-6 left-6 flex items-center gap-2">
                             <div className={`px-2 py-1 rounded-sm text-[9px] font-bold uppercase tracking-wider border ${currentStudyItem.type === 'word' ? 'bg-emerald-900/30 border-emerald-500/30 text-emerald-400' : currentStudyItem.type === 'phrase' ? 'bg-amber-900/30 border-amber-500/30 text-amber-400' : 'bg-cyan-900/30 border-cyan-500/30 text-cyan-400'}`}>
                                 {currentStudyItem.type}
                             </div>
                         </div>
                         <div className="absolute top-6 right-6">
                            <button onClick={(e) => { e.stopPropagation(); playPronunciation(currentStudyItem.id, currentStudyItem.text); }} className="p-2 text-zinc-500 hover:text-[#00f3ff] transition-colors bg-zinc-900/50 rounded-full">
                                <Volume2 size={20} />
                            </button>
                         </div>

                         <h2 className="text-4xl font-bold text-white text-center font-serif leading-tight">{currentStudyItem.text}</h2>

                         {currentStudyItem.bookTitle && (
                             <p className="absolute bottom-6 text-zinc-600 text-xs font-mono uppercase tracking-widest">{currentStudyItem.bookTitle.substring(0, 30)}</p>
                         )}
                         <div className="absolute bottom-6 right-6 text-[#00f3ff] text-[10px] animate-pulse font-mono">CLICK_TO_REVEAL_DATA</div>
                     </div>

                     {/* Back Side */}
                     <div className="absolute inset-0 backface-hidden rotate-y-180 bg-[#050505] border border-[#00f3ff]/30 rounded-xl p-10 flex flex-col shadow-[0_0_30px_rgba(0,243,255,0.1)] relative">
                         <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-[#00f3ff] to-transparent"></div>

                         <div className="flex items-center justify-between mb-6">
                             <h3 className="text-[#00f3ff] font-bold font-mono text-sm uppercase tracking-wider flex items-center gap-2">
                                <BookOpen size={16} />
                                ANALYSIS_MATRIX
                             </h3>
                             <button 
                                onClick={handleTranslateFlashcard}
                                className={`text-xs flex items-center gap-2 px-2 py-1 rounded-sm border transition-all ${showTranslatedCard ? 'bg-emerald-900/30 border-emerald-500/50 text-emerald-400' : 'bg-zinc-900 border-zinc-800 text-zinc-500 hover:text-[#00f3ff]'}`}
                             >
                                 {isTranslatingCard ? <Loader2 size={12} className="animate-spin" /> : <Languages size={12} />}
                                 {showTranslatedCard ? "SHOW_SOURCE" : "TRANSLATE"}
                             </button>
                         </div>

                         <div className="flex-1 overflow-y-auto custom-scrollbar pr-2 relative">
                             {isCurrentItemLoading ? (
                                 <div className="absolute inset-0 flex items-center justify-center flex-col gap-3 text-zinc-500">
                                     <Loader2 size={32} className="animate-spin text-[#00f3ff]" />
                                     <span className="text-xs font-mono animate-pulse">DECODING_NEURAL_PATHWAYS...</span>
                                 </div>
                             ) : (
                                 <div className="text-sm leading-relaxed text-zinc-300 font-medium">
                                     {formatAnalysisText(activeDefinition || "No definition data available.")}
                                 </div>
                             )}
                         </div>

                         {currentStudyItem.comment && (
                             <div className="mt-4 pt-4 border-t border-zinc-900">
                                 <div className="flex items-center gap-2 text-amber-500 text-xs font-bold mb-1 uppercase font-mono">
                                     <Quote size={12} /> USER_NOTE
                                 </div>
                                 <p className="text-zinc-500 text-xs italic pl-4 border-l border-amber-500/20">{currentStudyItem.comment}</p>
                             </div>
                         )}
                     </div>
                 </div>
             </div>

             {/* Navigation */}
             <div className="mt-8 flex items-center gap-8">
                 <button 
                    onClick={() => { setIsFlipped(false); setCurrentFlashcardIndex(prev => Math.max(0, prev - 1)); }}
                    disabled={currentFlashcardIndex === 0}
                    className="p-3 rounded-full border border-zinc-800 text-zinc-500 hover:text-[#00f3ff] hover:border-[#00f3ff] transition-all disabled:opacity-30 disabled:cursor-not-allowed hover:scale-110"
                 >
                     <ChevronLeft size={24} />
                 </button>
                 <button 
                    onClick={() => { setIsFlipped(false); setCurrentFlashcardIndex(prev => Math.min(filteredItems.length - 1, prev + 1)); }}
                    disabled={currentFlashcardIndex === filteredItems.length - 1}
                    className="p-3 rounded-full border border-zinc-800 text-zinc-500 hover:text-[#00f3ff] hover:border-[#00f3ff] transition-all disabled:opacity-30 disabled:cursor-not-allowed hover:scale-110"
                 >
                     <ChevronRight size={24} />
                 </button>
             </div>
        </div>
    );
  };

  const renderList = () => (
    <div className="h-full overflow-y-auto custom-scrollbar p-1">
        {filteredItems.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-full text-zinc-600 space-y-4 opacity-50">
                <NotebookIcon size={48} />
                <p className="font-mono text-xs uppercase tracking-widest">NO_DATA_LOGGED</p>
            </div>
        ) : (
            <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4 pb-20">
                {filteredItems.map(item => (
                    <div key={item.id} className="group relative bg-[#0a0a0c] border border-zinc-800 p-5 rounded-lg hover:border-[#00f3ff]/50 transition-all duration-300 hover:shadow-[0_0_20px_rgba(0,0,0,0.5)] flex flex-col">
                        <div className="flex justify-between items-start mb-3">
                            <div className={`px-1.5 py-0.5 rounded-sm text-[9px] font-bold uppercase tracking-wider border ${
                                item.type === 'word' ? 'bg-emerald-900/20 border-emerald-500/20 text-emerald-500' :
                                item.type === 'phrase' ? 'bg-amber-900/20 border-amber-500/20 text-amber-500' :
                                'bg-cyan-900/20 border-cyan-500/20 text-cyan-500'
                            }`}>
                                {item.type}
                            </div>
                            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                <button onClick={() => generateStickyNote(item)} className="p-1.5 text-zinc-500 hover:text-[#00f3ff] transition-colors rounded hover:bg-zinc-900" title="Export Sticky"><ImageDown size={14} /></button>
                                <button onClick={() => playPronunciation(item.id, item.text)} className={`p-1.5 text-zinc-500 hover:text-[#00f3ff] transition-colors rounded hover:bg-zinc-900 ${playingId === item.id ? 'text-[#00f3ff] animate-pulse' : ''}`} title="Pronounce"><Volume2 size={14} /></button>
                                <button onClick={() => onDelete(item.id)} className="p-1.5 text-zinc-500 hover:text-[#ff003c] transition-colors rounded hover:bg-zinc-900" title="Delete"><Trash2 size={14} /></button>
                            </div>
                        </div>

                        <h3 className="text-lg font-bold text-white mb-2 leading-tight font-serif break-words">{item.text}</h3>

                        {item.definition && (
                            <div className="mb-3 pl-3 border-l-2 border-zinc-800 text-xs text-zinc-400 leading-relaxed line-clamp-4">
                                {item.definition.split('\n')[0]}
                            </div>
                        )}

                        <div className="mt-auto pt-3 border-t border-zinc-900 flex items-center justify-between text-[10px] text-zinc-600 font-mono">
                            <div className="flex items-center gap-2">
                                <Clock size={10} />
                                <span>{new Date(item.timestamp).toLocaleDateString()}</span>
                            </div>
                            {item.bookTitle && (
                                <div className="flex items-center gap-1 max-w-[120px]">
                                    <Book size={10} />
                                    <span className="truncate" title={item.bookTitle}>{item.bookTitle}</span>
                                </div>
                            )}
                        </div>
                    </div>
                ))}
            </div>
        )}
    </div>
  );

  return (
    <div className="h-full flex flex-col font-sans text-zinc-100 text-left relative" style={fontStyle}>
       <style>{`
          .perspective-1000 { perspective: 1000px; -webkit-perspective: 1000px; } 
          .backface-hidden { backface-visibility: hidden; -webkit-backface-visibility: hidden; z-index: 2; } 
          .rotate-y-180 { transform: rotateY(180deg); -webkit-transform: rotateY(180deg); } 
          .transform-style-3d { transform-style: preserve-3d; -webkit-transform-style: preserve-3d; }
          .custom-scrollbar-visible::-webkit-scrollbar { width: 6px; }
          .custom-scrollbar-visible::-webkit-scrollbar-track { background: rgba(0,0,0,0.3); border-radius: 3px; }
          .custom-scrollbar-visible::-webkit-scrollbar-thumb { background: #ff003c; border-radius: 3px; box-shadow: 0 0 10px rgba(255,0,60,0.5); }
       `}</style>

       {/* Toolbar */}
       <div className="bg-zinc-950/80 p-3 rounded-lg border border-cyan-900/40 mb-4 flex items-center justify-between shrink-0 shadow-[0_0_15px_rgba(0,243,255,0.05)] w-full flex-nowrap gap-2 z-10 transition-all duration-300">
           <div className="flex items-center gap-4 flex-1">
               <div className="flex items-center gap-2 text-white font-bold tracking-widest uppercase font-mono text-xs shrink-0">
                   <NotebookIcon size={18} className="text-[#00f3ff]" />
                   <span>Mem_Log</span>
               </div>

               {/* Divider */}
               <div className="w-[1px] h-4 bg-zinc-800"></div>

               {/* Filters - Use visibility/width to maintain layout stability during flashcard mode */}
               {/* When isFlashcardMode is true, we hide these but keep the structure to avoid jumping, or we animate them out gracefully */}
               {/* Using opacity-0 + pointer-events-none keeps them taking up space if we want exact layout match, but shrinking them looks cleaner. */}
               {/* To satisfy "width of top controller changed", we ensure the CONTAINER width is fixed (w-full on parent) and flex behavior is stable. */}
               <div className={`flex items-center gap-1 overflow-hidden transition-all duration-300 ease-in-out ${isFlashcardMode ? 'opacity-0 pointer-events-none max-w-0' : 'opacity-100 max-w-[400px]'}`}>
                   {(['all', 'word', 'phrase', 'sentence'] as const).map(f => (
                       <button 
                          key={f}
                          onClick={() => setActiveFilter(f)}
                          className={`px-3 py-1 rounded-sm text-[10px] font-bold uppercase tracking-wider transition-all ${activeFilter === f ? 'bg-[#00f3ff]/20 text-[#00f3ff] border border-[#00f3ff]/30' : 'text-zinc-500 hover:text-zinc-300'}`}
                       >
                          {f}
                       </button>
                   ))}
               </div>
           </div>

           <div className="flex items-center gap-3 shrink-0">
               {/* Sort - Hide in flashcard mode */}
               <div className={`flex items-center gap-2 mr-2 transition-all duration-300 ${isFlashcardMode ? 'opacity-0 pointer-events-none w-0 overflow-hidden' : 'opacity-100 w-auto'}`}>
                   <span className="text-[10px] text-zinc-600 font-mono uppercase whitespace-nowrap">Sort:</span>
                   <select 
                      value={sortOrder}
                      onChange={(e) => setSortOrder(e.target.value as SortOrder)}
                      className="bg-[#050505] border border-zinc-800 text-[10px] text-[#00f3ff] font-mono uppercase rounded-sm px-2 py-1 outline-none focus:border-[#00f3ff]"
                   >
                       <option value="newest">Time (New)</option>
                       <option value="oldest">Time (Old)</option>
                       <option value="az">A-Z</option>
                       <option value="za">Z-A</option>
                   </select>
               </div>

               <button 
                  onClick={isFlashcardMode ? () => setIsFlashcardMode(false) : startFlashcards}
                  disabled={filteredItems.length === 0}
                  className={`flex items-center gap-2 px-4 py-1.5 rounded-sm text-xs font-bold font-mono uppercase transition-all shadow-[0_0_10px_rgba(0,243,255,0.3)] min-w-[150px] justify-center ${isFlashcardMode ? 'bg-zinc-800 text-zinc-400 hover:bg-zinc-700' : 'bg-[#00f3ff] text-black hover:bg-[#00c2cc]'} ${filteredItems.length === 0 ? 'opacity-50 cursor-not-allowed' : ''}`}
               >
                   {isFlashcardMode ? <XIcon size={14} /> : <Zap size={14} fill="currentColor" />}
                   {isFlashcardMode ? "End_Session" : "Neural_Flashcards"}
               </button>
           </div>
       </div>

       {/* Content Area */}
       <div className="flex-1 min-h-0 relative">
          {isFlashcardMode ? renderFlashcards() : renderList()}
       </div>

    </div>
  );
};
